insert into public.questions (id, topic, source, q, opts, ans_idx, exp, category, category_icon, is_active)
values
(4028, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Management is best defined as:', '["The process of controlling staff only","The process of planning, organizing, directing, and controlling resources to achieve organizational goals","The act of supervising junior nurses","Delegating all responsibilities to subordinates"]'::jsonb, 1, 'Management is the process of planning, organizing, directing, and controlling resources to achieve organisational goals.', 'Ethics, Law & Management', '⚖️', true),
(4029, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which management function should always come first?', '["Organizing","Directing","Planning","Controlling"]'::jsonb, 2, 'Planning sets the direction and goals that organizing, directing, and controlling all follow from, so it is the first management function.', 'Ethics, Law & Management', '⚖️', true),
(4030, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The primary goal of nursing management is to:', '["Increase hospital revenue","Improve patient outcomes through effective use of resources","Reduce nurses'' workload","Increase doctors'' efficiency"]'::jsonb, 1, 'Nursing management exists to support effective, efficient use of resources in service of better patient outcomes, not as an end in itself.', 'Ethics, Law & Management', '⚖️', true),
(4031, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which management level is responsible for policy formulation?', '["First-line managers","Middle managers","Top management","Charge nurses"]'::jsonb, 2, 'Top management sets overall organisational policy and strategic direction.', 'Ethics, Law & Management', '⚖️', true),
(4032, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A nurse manager preparing the monthly duty roster is performing which management function?', '["Planning","Organizing","Directing","Controlling"]'::jsonb, 1, 'Preparing a duty roster arranges staff and resources to accomplish planned goals, which is the organizing function.', 'Ethics, Law & Management', '⚖️', true),
(4033, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which leadership style encourages staff participation in decision-making?', '["Autocratic","Democratic","Laissez-faire","Bureaucratic"]'::jsonb, 1, 'Democratic leadership actively involves staff in decision-making.', 'Ethics, Law & Management', '⚖️', true),
(4034, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which leadership style is most appropriate during cardiopulmonary resuscitation?', '["Democratic","Autocratic","Laissez-faire","Transformational"]'::jsonb, 1, 'During CPR, clear, rapid, directive instructions from one leader are needed, making autocratic leadership most appropriate in that emergency moment.', 'Ethics, Law & Management', '⚖️', true),
(4035, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Delegation means:', '["Transferring responsibility only","Assigning responsibility and authority while maintaining accountability","Giving away accountability","Asking another nurse to perform your duty permanently"]'::jsonb, 1, 'Delegation means assigning responsibility and authority for a task to someone else while the delegator retains ultimate accountability.', 'Ethics, Law & Management', '⚖️', true),
(4036, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Accountability remains with:', '["The person receiving the task","The nurse manager","The patient","The hospital director"]'::jsonb, 1, 'In delegation, the person who delegates the task retains accountability even though responsibility for the task itself is assigned to someone else.', 'Ethics, Law & Management', '⚖️', true),
(4037, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which task should NOT be delegated to a nursing assistant?', '["Bed making","Feeding a stable patient","Assessment of pain","Transporting stable patients"]'::jsonb, 2, 'Clinical judgement tasks like pain assessment require nursing scope of practice and should not be delegated to unlicensed assistive personnel.', 'Ethics, Law & Management', '⚖️', true),
(4038, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The first step in problem-solving is:', '["Selecting solutions","Evaluating outcomes","Identifying the problem","Implementing solutions"]'::jsonb, 2, 'Problem-solving begins with clearly identifying and defining the actual problem before generating or selecting solutions.', 'Ethics, Law & Management', '⚖️', true),
(4039, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which communication method provides immediate feedback?', '["Memorandum","Email","Face-to-face communication","Notice board"]'::jsonb, 2, 'Face-to-face communication allows immediate two-way feedback, unlike written or asynchronous methods.', 'Ethics, Law & Management', '⚖️', true),
(4040, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which of the following is an example of downward communication?', '["Staff nurse reporting to matron","Hospital director giving instructions to ward managers","Communication between colleagues","Communication between two hospitals"]'::jsonb, 1, 'Downward communication flows from higher to lower levels of the organisational hierarchy, such as a director instructing ward managers.', 'Ethics, Law & Management', '⚖️', true),
(4041, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Span of control refers to:', '["Number of hospitals supervised","Number of employees supervised by one manager","Hospital budget","Number of patients admitted"]'::jsonb, 1, 'Span of control refers to the number of subordinates a manager directly supervises.', 'Ethics, Law & Management', '⚖️', true),
(4042, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The chain of command ensures:', '["Equal salaries","Proper reporting relationships","Patient discharge","Drug procurement"]'::jsonb, 1, 'The chain of command establishes clear lines of authority and reporting relationships within an organisation.', 'Ethics, Law & Management', '⚖️', true),
(4043, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which motivation theory was developed by Abraham Maslow?', '["Scientific Management","Hierarchy of Needs","Human Relations Theory","Systems Theory"]'::jsonb, 1, 'Abraham Maslow developed the Hierarchy of Needs motivational theory.', 'Ethics, Law & Management', '⚖️', true),
(4044, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'According to Maslow, physiological needs include:', '["Recognition","Security","Food and water","Self-esteem"]'::jsonb, 2, 'Maslow''s physiological needs are the most basic survival needs, including food and water.', 'Ethics, Law & Management', '⚖️', true),
(4045, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which quality improvement model is widely used in healthcare?', '["SWOT","PDSA Cycle","Fishbone Diagram","Gantt Chart"]'::jsonb, 1, 'The Plan-Do-Study-Act (PDSA) cycle is a widely used quality improvement model in healthcare.', 'Ethics, Law & Management', '⚖️', true),
(4046, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Continuous quality improvement primarily aims to:', '["Punish staff","Improve patient care continuously","Increase workload","Reduce documentation"]'::jsonb, 1, 'Continuous quality improvement aims to progressively improve patient care processes and outcomes over time.', 'Ethics, Law & Management', '⚖️', true),
(4047, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Clinical audit is conducted mainly to:', '["Discipline staff","Compare practice with standards","Recruit nurses","Increase hospital income"]'::jsonb, 1, 'Clinical audit compares actual practice against established standards to identify gaps for improvement.', 'Ethics, Law & Management', '⚖️', true),
(4048, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which management function involves determining the goals and objectives of a nursing unit?', '["Organizing","Planning","Directing","Controlling"]'::jsonb, 1, 'Setting the goals and objectives of a unit is the essence of the planning function.', 'Ethics, Law & Management', '⚖️', true),
(4049, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A nurse manager estimates the number of nurses required for the ICU next year. This activity is known as:', '["Staff appraisal","Human resource planning","Staff orientation","Supervision"]'::jsonb, 1, 'Forecasting future staffing needs is a form of human resource planning.', 'Ethics, Law & Management', '⚖️', true),
(4050, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which document outlines the duties and responsibilities of a staff nurse?', '["Ward report","Duty roster","Job description","Nursing care plan"]'::jsonb, 2, 'A job description formally outlines the duties, responsibilities, and expectations of a role.', 'Ethics, Law & Management', '⚖️', true),
(4051, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'One major purpose of a job description is to:', '["Determine patient diagnosis","Clarify staff responsibilities","Increase hospital income","Replace hospital policy"]'::jsonb, 1, 'A job description helps clarify what staff are responsible for in their role.', 'Ethics, Law & Management', '⚖️', true),
(4052, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A nurse manager assigning nurses according to their competence is applying the principle of:', '["Equity","Right person for the right job","Unity of command","Authority"]'::jsonb, 1, 'Matching staff assignments to their competence reflects the ''right person for the right job'' principle.', 'Ethics, Law & Management', '⚖️', true),
(4053, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which staffing pattern provides continuous nursing care by the same nurse throughout the patient''s hospital stay?', '["Functional nursing","Team nursing","Primary nursing","Case method"]'::jsonb, 2, 'Primary nursing assigns one nurse to provide continuous, comprehensive care to a patient throughout their stay.', 'Ethics, Law & Management', '⚖️', true),
(4054, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'In functional nursing, care is organized according to:', '["Patient diagnosis","Nursing tasks","Family preference","Bed numbers"]'::jsonb, 1, 'Functional nursing organises care delivery around specific tasks rather than the whole patient.', 'Ethics, Law & Management', '⚖️', true),
(4055, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which nursing care delivery system promotes continuity and accountability?', '["Functional nursing","Team nursing","Primary nursing","Modular nursing"]'::jsonb, 2, 'Primary nursing''s continuity of a single accountable nurse promotes both continuity of care and clear accountability.', 'Ethics, Law & Management', '⚖️', true),
(4056, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Team nursing is most effective when:', '["There is poor communication","Team members cooperate effectively","Only one nurse performs all procedures","There is no team leader"]'::jsonb, 1, 'Team nursing depends on effective cooperation and communication among team members to succeed.', 'Ethics, Law & Management', '⚖️', true),
(4057, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The nurse responsible for coordinating the activities of a nursing team is the:', '["Ward orderly","Team leader","Pharmacist","Medical officer"]'::jsonb, 1, 'The team leader coordinates and directs the activities of the nursing team members.', 'Ethics, Law & Management', '⚖️', true),
(4058, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A nursing shift handover should include all EXCEPT:', '["Patient''s condition","Treatment given","Confidential personal opinions","Pending investigations"]'::jsonb, 2, 'Handover should focus on relevant clinical information; unverified confidential personal opinions have no place in a professional handover.', 'Ethics, Law & Management', '⚖️', true),
(4059, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'An effective handover should be:', '["Brief but comprehensive","Based on assumptions","Conducted without documentation","Done only when convenient"]'::jsonb, 0, 'An effective handover conveys all necessary information concisely without unnecessary detail.', 'Ethics, Law & Management', '⚖️', true),
(4060, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which of the following is the best indicator of adequate staffing?', '["Number of beds","Number of doctors","Patient acuity and workload","Hospital size"]'::jsonb, 2, 'Staffing adequacy is best judged by matching staff numbers to actual patient acuity and workload, not headcount alone.', 'Ethics, Law & Management', '⚖️', true),
(4061, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The main purpose of a nursing duty roster is to:', '["Reduce annual leave","Ensure equitable staff allocation","Punish absenteeism","Increase overtime"]'::jsonb, 1, 'A duty roster''s main purpose is to distribute staffing fairly and adequately across shifts.', 'Ethics, Law & Management', '⚖️', true),
(4062, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A nurse who reports late for duty without valid reason is guilty of:', '["Professional accountability","Negligence","Indiscipline","Confidentiality breach"]'::jsonb, 2, 'Reporting late without valid reason is a disciplinary matter classified as indiscipline.', 'Ethics, Law & Management', '⚖️', true),
(4063, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which management skill is most important for resolving interpersonal disputes?', '["Technical skill","Financial skill","Communication skill","Computer skill"]'::jsonb, 2, 'Strong communication skills are essential for mediating and resolving interpersonal conflicts.', 'Ethics, Law & Management', '⚖️', true),
(4064, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which leadership theory emphasizes adapting leadership style to the situation?', '["Trait theory","Great man theory","Situational leadership theory","Bureaucratic theory"]'::jsonb, 2, 'Situational leadership theory holds that the most effective leadership style depends on the specific situation and follower readiness.', 'Ethics, Law & Management', '⚖️', true),
(4065, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A transformational leader is most likely to:', '["Inspire staff to achieve shared goals","Depend only on rules","Avoid staff participation","Resist innovation"]'::jsonb, 0, 'Transformational leaders inspire and motivate staff toward a shared vision and goals.', 'Ethics, Law & Management', '⚖️', true),
(4066, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The primary aim of staff development programmes is to:', '["Increase workload","Improve competence and performance","Delay promotion","Reduce accountability"]'::jsonb, 1, 'Staff development programmes aim to build and maintain staff competence and performance.', 'Ethics, Law & Management', '⚖️', true),
(4067, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which of the following is considered an in-service education programme?', '["Orientation for newly employed nurses","Annual leave","Retirement seminar","Salary negotiation"]'::jsonb, 0, 'Orientation for newly employed nurses is a form of in-service education preparing them for their new role.', 'Ethics, Law & Management', '⚖️', true),
(4068, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The process of estimating the financial needs of a nursing unit is known as:', '["Auditing","Budgeting","Procurement","Inventory"]'::jsonb, 1, 'Budgeting is the process of estimating and planning for a unit''s financial needs.', 'Ethics, Law & Management', '⚖️', true),
(4069, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A budget is primarily used to:', '["Discipline employees","Plan and control financial resources","Increase hospital admission","Determine patient diagnosis"]'::jsonb, 1, 'A budget is a tool for planning and controlling how financial resources are allocated and spent.', 'Ethics, Law & Management', '⚖️', true),
(4070, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which type of budget is most concerned with day-to-day hospital expenses?', '["Capital budget","Operating budget","Cash budget","Master budget"]'::jsonb, 1, 'The operating budget covers routine, day-to-day operational expenses.', 'Ethics, Law & Management', '⚖️', true),
(4071, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The purchase of a new ventilator should be included in the:', '["Operating budget","Capital budget","Salary budget","Revenue budget"]'::jsonb, 1, 'Major equipment purchases like a ventilator are capital expenditures, funded through the capital budget.', 'Ethics, Law & Management', '⚖️', true),
(4072, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Inventory management primarily aims to:', '["Eliminate documentation","Ensure availability of supplies","Increase hospital costs","Reduce patient admissions"]'::jsonb, 1, 'Inventory management exists to ensure needed supplies are consistently available without excess waste.', 'Ethics, Law & Management', '⚖️', true),
(4073, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The first step in inventory control is:', '["Issuing supplies","Identifying required items","Disposing expired items","Annual auditing"]'::jsonb, 1, 'Inventory control begins with identifying which items are actually required.', 'Ethics, Law & Management', '⚖️', true),
(4074, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The abbreviation FIFO in store management means:', '["First In, First Out","First Into Final Order","Fast Inventory Follow-up Operation","Final Item First Out"]'::jsonb, 0, 'FIFO stands for First In, First Out, a stock rotation method.', 'Ethics, Law & Management', '⚖️', true),
(4075, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'FIFO is mainly used to:', '["Increase stock","Prevent expiry of supplies","Delay procurement","Increase waste"]'::jsonb, 1, 'FIFO ensures older stock is used before newer stock, helping prevent items expiring unused.', 'Ethics, Law & Management', '⚖️', true),
(4076, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which document authorizes the release of items from the hospital store?', '["Laboratory request form","Store requisition voucher","Nursing care plan","Incident report"]'::jsonb, 1, 'A store requisition voucher is the formal document authorising release of items from hospital stores.', 'Ethics, Law & Management', '⚖️', true),
(4077, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A stock-taking exercise is conducted mainly to:', '["Employ more staff","Determine available supplies","Increase hospital income","Evaluate patient outcomes"]'::jsonb, 1, 'Stock-taking verifies and quantifies the supplies actually available on hand.', 'Ethics, Law & Management', '⚖️', true),
(4078, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The nurse manager discovers expired intravenous fluids in the ward. The most appropriate action is to:', '["Continue using them","Remove and report them according to policy","Relabel the expiry date","Return them to patients"]'::jsonb, 1, 'Expired IV fluids pose a safety risk and should be removed from use and reported according to institutional policy.', 'Ethics, Law & Management', '⚖️', true),
(4079, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The most important principle of resource management is:', '["Waste of supplies","Efficient utilization of available resources","Keeping excess stock","Ignoring shortages"]'::jsonb, 1, 'Efficient utilisation of available resources is the core principle underlying sound resource management.', 'Ethics, Law & Management', '⚖️', true),
(4080, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'An incident report should be completed when:', '["A medication error occurs","A patient is discharged","A nurse resumes duty","The ward is cleaned"]'::jsonb, 0, 'A medication error is a reportable incident requiring completion of an incident report.', 'Ethics, Law & Management', '⚖️', true),
(4081, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The primary purpose of an incident report is to:', '["Punish staff","Improve patient safety and prevent recurrence","Replace patient documentation","Determine salary"]'::jsonb, 1, 'Incident reports exist primarily to identify system issues and improve patient safety, not to assign blame.', 'Ethics, Law & Management', '⚖️', true),
(4082, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Risk management in nursing focuses on:', '["Preventing harm to patients and staff","Increasing litigation","Increasing workload","Reducing communication"]'::jsonb, 0, 'Risk management in nursing focuses on identifying and mitigating hazards to prevent harm to patients and staff.', 'Ethics, Law & Management', '⚖️', true),
(4083, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which document serves as a legal record of nursing care?', '["Incident report","Nursing documentation","Leave application","Budget proposal"]'::jsonb, 1, 'Nursing documentation serves as the legal record of the care that was provided.', 'Ethics, Law & Management', '⚖️', true),
(4084, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Good nursing documentation should be:', '["Accurate, timely, and objective","Delayed until the end of the shift","Based on assumptions","Written by another nurse"]'::jsonb, 0, 'Good documentation should accurately, objectively, and promptly reflect the care given.', 'Ethics, Law & Management', '⚖️', true),
(4085, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A nurse who documents care not actually provided has committed:', '["Advocacy","Falsification of records","Delegation","Supervision"]'::jsonb, 1, 'Recording care that was not actually provided constitutes falsification of records, a serious professional and legal violation.', 'Ethics, Law & Management', '⚖️', true),
(4086, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which principle guides the confidentiality of patient records?', '["Beneficence only","Respect for privacy and professional ethics","Financial accountability","Administrative policy only"]'::jsonb, 1, 'Confidentiality of patient records is guided by respect for patient privacy and professional ethical standards.', 'Ethics, Law & Management', '⚖️', true),
(4087, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The overall responsibility of the nurse manager is to ensure:', '["Patient safety, quality care, and efficient use of resources","Only financial profit","Only staff satisfaction","Only physician convenience"]'::jsonb, 0, 'The nurse manager holds overall responsibility for patient safety, quality of care, and efficient resource use on the unit.', 'Ethics, Law & Management', '⚖️', true),
(4088, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A newly employed nurse repeatedly reports late for duty despite verbal counseling. As the nurse manager, your FIRST action should be to:', '["Recommend dismissal immediately","Document the incidents and follow the hospital disciplinary procedure","Ignore the behaviour","Transfer the nurse to another ward"]'::jsonb, 1, 'Documenting incidents and following the disciplinary process ensures fairness and a clear record before further action is taken.', 'Ethics, Law & Management', '⚖️', true),
(4089, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The ICU manager notices an increase in medication errors during the night shift. The priority action is to:', '["Suspend all night-duty nurses","Investigate the root causes before implementing corrective measures","Report all nurses to the Nursing Council","Reduce the number of patients admitted"]'::jsonb, 1, 'Investigating root causes before acting ensures corrective measures address the real underlying problem rather than just the symptom.', 'Ethics, Law & Management', '⚖️', true),
(4090, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A patient falls while attempting to go to the toilet without assistance. The nurse manager should FIRST:', '["Complete the incident report only","Assess the patient for injuries and provide immediate care","Inform the media","Blame the nurse on duty"]'::jsonb, 1, 'The immediate priority after any patient fall is assessing for injury and providing needed care.', 'Ethics, Law & Management', '⚖️', true),
(4091, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which leadership style is most appropriate during a mass casualty emergency?', '["Democratic","Laissez-faire","Autocratic","Affiliative"]'::jsonb, 2, 'Directive, autocratic leadership suits the need for rapid, coordinated action during a mass casualty emergency.', 'Ethics, Law & Management', '⚖️', true),
(4092, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The nurse manager observes that staff morale is declining due to excessive workload. Which management action is most appropriate?', '["Ignore complaints","Assess staffing needs and redistribute workload fairly","Increase disciplinary actions","Cancel staff meetings"]'::jsonb, 1, 'Reviewing and fairly redistributing workload addresses the root cause of declining morale from excessive burden.', 'Ethics, Law & Management', '⚖️', true),
(4093, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which indicator best measures the quality of nursing care?', '["Number of visitors","Patient outcomes and satisfaction","Number of doctors","Number of hospital beds"]'::jsonb, 1, 'Patient outcomes and satisfaction most directly reflect the quality of nursing care delivered.', 'Ethics, Law & Management', '⚖️', true),
(4094, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Clinical governance primarily aims to:', '["Increase hospital profits","Continuously improve the quality and safety of healthcare","Increase paperwork only","Reduce staff salaries"]'::jsonb, 1, 'Clinical governance is the framework through which organisations continuously improve the quality and safety of care.', 'Ethics, Law & Management', '⚖️', true),
(4095, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The BEST method for identifying the cause of repeated nursing errors is:', '["Guesswork","Root cause analysis","Staff transfer","Annual leave"]'::jsonb, 1, 'Root cause analysis systematically identifies the underlying causes of recurring errors.', 'Ethics, Law & Management', '⚖️', true),
(4096, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A nurse delegates the administration of intravenous medication to a nursing assistant. This action is:', '["Appropriate","Acceptable if supervised","Inappropriate because it exceeds the assistant''s scope of practice","Recommended during emergencies"]'::jsonb, 2, 'IV medication administration exceeds a nursing assistant''s scope of practice and should not be delegated to them.', 'Ethics, Law & Management', '⚖️', true),
(4097, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The nurse manager receives a complaint from a patient''s relative. The FIRST response should be to:', '["Defend the staff immediately","Listen carefully and gather all relevant facts","Ignore the complaint","Refer the relative to security"]'::jsonb, 1, 'Listening and gathering the facts first ensures a complaint is properly understood before any response or action.', 'Ethics, Law & Management', '⚖️', true),
(4098, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which principle should guide every disciplinary action?', '["Personal opinion","Fairness and due process","Friendship","Seniority"]'::jsonb, 1, 'Fairness and due process must guide every disciplinary action to be ethical and legally sound.', 'Ethics, Law & Management', '⚖️', true),
(4099, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A staff nurse consistently exceeds performance expectations. The BEST management response is to:', '["Ignore the performance","Recognize and reward excellent performance","Assign all difficult patients to the nurse","Increase criticism"]'::jsonb, 1, 'Recognising and rewarding strong performance reinforces and sustains it.', 'Ethics, Law & Management', '⚖️', true),
(4100, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which management tool helps identify a unit''s strengths, weaknesses, opportunities, and threats?', '["Gantt chart","SWOT analysis","Fishbone diagram","Flowchart"]'::jsonb, 1, 'SWOT analysis identifies an organisation''s strengths, weaknesses, opportunities, and threats.', 'Ethics, Law & Management', '⚖️', true),
(4101, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'An ICU nurse refuses to comply with hand hygiene protocols. The nurse manager should FIRST:', '["Dismiss the nurse immediately","Reinforce infection prevention policies and investigate the reason for non-compliance","Ignore the behaviour","Report directly to the media"]'::jsonb, 1, 'Reinforcing policy while investigating the underlying reason addresses both immediate safety and the root cause of non-compliance.', 'Ethics, Law & Management', '⚖️', true),
(4102, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which is the MOST effective strategy for preventing healthcare-associated infections?', '["Limiting patient movement","Strict adherence to infection prevention and control (IPC) measures","Reducing documentation","Isolating all patients"]'::jsonb, 1, 'Strict adherence to infection prevention and control measures is the most effective strategy for preventing healthcare-associated infections.', 'Ethics, Law & Management', '⚖️', true),
(4103, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Evidence-based management means decisions are based on:', '["Rumours","Research evidence, clinical expertise, and organizational data","Personal opinion only","Political influence"]'::jsonb, 1, 'Evidence-based management integrates research evidence, clinical expertise, and organisational data into decisions.', 'Ethics, Law & Management', '⚖️', true),
(4104, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The BEST indicator of effective delegation is:', '["Increased complaints","Safe completion of assigned tasks with appropriate supervision","Staff confusion","Reduced documentation"]'::jsonb, 1, 'Effective delegation is best judged by whether the task was completed safely with appropriate oversight.', 'Ethics, Law & Management', '⚖️', true),
(4105, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which management principle promotes employee participation in decision-making?', '["Centralization","Decentralization","Discipline","Unity of command"]'::jsonb, 1, 'Decentralisation distributes decision-making authority, promoting employee participation.', 'Ethics, Law & Management', '⚖️', true),
(4106, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A nurse manager encourages innovation and professional growth among staff. This demonstrates:', '["Transactional leadership","Transformational leadership","Bureaucratic leadership","Autocratic leadership"]'::jsonb, 1, 'Encouraging innovation and staff growth is characteristic of transformational leadership.', 'Ethics, Law & Management', '⚖️', true),
(4107, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The overall goal of quality improvement programmes is to:', '["Reduce staffing","Improve patient outcomes through continuous system improvement","Increase documentation","Reduce communication"]'::jsonb, 1, 'Quality improvement programmes ultimately aim to improve patient outcomes through ongoing system-level improvement.', 'Ethics, Law & Management', '⚖️', true),
(4108, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which of the following is the MOST valuable asset in healthcare management?', '["Buildings","Equipment","Human resources","Vehicles"]'::jsonb, 2, 'Staff (human resources) are consistently regarded as healthcare''s most valuable asset, since quality care depends on their skill and engagement.', 'Ethics, Law & Management', '⚖️', true),
(4109, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A nurse manager preparing an annual budget should first consider:', '["Staff preferences","Unit goals, workload, and previous expenditure","Personal opinion","Number of doctors"]'::jsonb, 1, 'A sound budget is grounded in the unit''s actual goals, expected workload, and historical spending patterns.', 'Ethics, Law & Management', '⚖️', true),
(4110, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The BEST approach to resolving conflict between two nurses is:', '["Ignore both nurses","Facilitate open communication and collaborative problem-solving","Transfer both nurses immediately","Suspend both nurses"]'::jsonb, 1, 'Facilitating open communication and collaborative problem-solving addresses the root of interpersonal conflict constructively.', 'Ethics, Law & Management', '⚖️', true),
(4111, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A patient experiences a medication error with no resulting harm. This event is classified as a:', '["Never event","Adverse event","Near miss","Sentinel event"]'::jsonb, 2, 'An error that reaches the patient but causes no harm is classified as a near miss.', 'Ethics, Law & Management', '⚖️', true),
(4112, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which document is MOST useful when evaluating nursing workload?', '["Duty roster","Acuity classification system","Salary register","Attendance register"]'::jsonb, 1, 'An acuity classification system quantifies patient care needs, making it the most useful tool for evaluating nursing workload.', 'Ethics, Law & Management', '⚖️', true),
(4113, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The nurse manager is responsible for ensuring informed consent is:', '["Ignored in emergencies","Properly obtained before procedures, except where legally exempt","Signed by nurses only","Completed after surgery"]'::jsonb, 1, 'Ensuring properly obtained informed consent (with recognised legal exceptions such as emergencies) is a core nurse manager responsibility.', 'Ethics, Law & Management', '⚖️', true),
(4114, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'An effective quality assurance programme is characterized by:', '["Continuous monitoring and improvement","Punishment only","Increased paperwork without evaluation","Staff criticism"]'::jsonb, 0, 'An effective quality assurance programme relies on continuous monitoring paired with ongoing improvement action.', 'Ethics, Law & Management', '⚖️', true),
(4115, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which factor contributes MOST to staff retention?', '["Poor supervision","Supportive leadership and professional development opportunities","Frequent disciplinary actions","Unfair scheduling"]'::jsonb, 1, 'Supportive leadership and opportunities for professional growth are strong drivers of staff retention.', 'Ethics, Law & Management', '⚖️', true),
(4116, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A nurse manager reviewing patient complaints notices a trend of delayed medication administration. The MOST appropriate action is to:', '["Blame the night staff","Conduct a quality improvement review to identify contributing factors","Ignore isolated complaints","Reduce patient admissions"]'::jsonb, 1, 'A structured quality improvement review identifies the contributing factors behind a trend like delayed medication administration.', 'Ethics, Law & Management', '⚖️', true),
(4117, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Benchmarking in healthcare is the process of:', '["Comparing performance with recognized best practices","Increasing hospital charges","Hiring more staff","Reducing supervision"]'::jsonb, 0, 'Benchmarking compares an organisation''s performance against recognised best-practice standards.', 'Ethics, Law & Management', '⚖️', true),
(4118, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which management skill is MOST important when leading multidisciplinary teams?', '["Clinical communication and coordination","Financial accounting","Engineering knowledge","Computer programming"]'::jsonb, 0, 'Coordinating multidisciplinary teams depends heavily on clear clinical communication.', 'Ethics, Law & Management', '⚖️', true),
(4119, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The primary aim of risk assessment in nursing management is to:', '["Increase workload","Identify hazards before harm occurs","Delay patient care","Reduce staff numbers"]'::jsonb, 1, 'Risk assessment aims to identify hazards proactively, before they result in patient harm.', 'Ethics, Law & Management', '⚖️', true),
(4120, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The nurse manager should review staffing levels based primarily on:', '["Nurse preferences","Patient acuity and workload","Public holidays","Hospital age"]'::jsonb, 1, 'Staffing levels should be driven primarily by patient acuity and workload, not fixed ratios alone.', 'Ethics, Law & Management', '⚖️', true),
(4121, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which quality tool is commonly used to identify the underlying causes of a problem?', '["Fishbone (Ishikawa) diagram","Duty roster","Organizational chart","Leave register"]'::jsonb, 0, 'The fishbone (Ishikawa) diagram is a structured tool for identifying the underlying causes of a problem.', 'Ethics, Law & Management', '⚖️', true),
(4122, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A manager who encourages staff to report errors without fear of unfair punishment is promoting a:', '["Punitive culture","Just culture","Blame culture","Competitive culture"]'::jsonb, 1, 'A just culture encourages open error reporting by focusing on system factors rather than unfair individual blame.', 'Ethics, Law & Management', '⚖️', true),
(4123, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The MOST appropriate action after identifying a patient safety risk is to:', '["Ignore it","Implement measures to reduce or eliminate the risk","Wait for an incident to occur","Document only"]'::jsonb, 1, 'Once a safety risk is identified, the appropriate response is to implement measures that reduce or eliminate it.', 'Ethics, Law & Management', '⚖️', true),
(4124, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'An effective preceptor should primarily:', '["Criticize new staff publicly","Guide, supervise, and support learning","Delegate all work to students","Avoid giving feedback"]'::jsonb, 1, 'An effective preceptor''s core role is to guide, supervise, and support the learner''s development.', 'Ethics, Law & Management', '⚖️', true),
(4125, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The nurse manager should evaluate staff performance based on:', '["Objective standards and measurable outcomes","Personal relationships","Rumours","Length of employment only"]'::jsonb, 0, 'Performance should be evaluated against objective, measurable standards rather than subjective impressions.', 'Ethics, Law & Management', '⚖️', true),
(4126, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The BEST strategy for reducing burnout among ICU nurses is to:', '["Increase overtime","Promote adequate staffing, rest periods, and psychological support","Eliminate annual leave","Reduce communication"]'::jsonb, 1, 'Adequate staffing, rest, and psychological support directly address the drivers of ICU nurse burnout.', 'Ethics, Law & Management', '⚖️', true),
(4127, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'An effective nurse manager demonstrates accountability by:', '["Delegating responsibility and abandoning supervision","Taking responsibility for management decisions and ensuring quality patient care","Avoiding difficult decisions","Ignoring staff concerns"]'::jsonb, 1, 'Taking responsibility for decisions and their outcomes is the essence of managerial accountability.', 'Ethics, Law & Management', '⚖️', true),
(4128, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A newly employed ICU nurse is unable to operate a mechanical ventilator safely. The nurse manager should FIRST:', '["Issue a written warning","Assign the nurse to independent ventilator care","Arrange supervised training and assess competency","Transfer the nurse to another hospital"]'::jsonb, 2, 'Supervised training and competency assessment address a specific identified skill gap before independent practice resumes.', 'Ethics, Law & Management', '⚖️', true),
(4129, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which management principle is best demonstrated when an ICU nurse is assigned only patients requiring advanced critical care skills?', '["Unity of command","Span of control","Right person for the right job","Scalar chain"]'::jsonb, 2, 'Assigning nurses matched to the complexity of care required exemplifies the ''right person for the right job'' principle.', 'Ethics, Law & Management', '⚖️', true),
(4130, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The MOST important objective of orientation for newly posted ICU nurses is to:', '["Familiarize them with hospital rules only","Ensure safe, competent patient care","Introduce salary structure","Explain annual leave procedures"]'::jsonb, 1, 'The core purpose of ICU orientation is to prepare nurses to deliver safe, competent patient care in that specialised setting.', 'Ethics, Law & Management', '⚖️', true),
(4131, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A nurse manager discovers that a staff nurse has administered the wrong medication but reported it immediately. The BEST response is to:', '["Dismiss the nurse immediately","Assess the patient, ensure appropriate treatment, document the event, and investigate contributing factors","Ignore the error because it was reported","Publicly criticize the nurse"]'::jsonb, 1, 'Prompt disclosure, patient assessment/treatment, documentation, and investigation together address both immediate safety and systemic learning after a self-reported error.', 'Ethics, Law & Management', '⚖️', true),
(4132, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which of the following best describes a sentinel event?', '["Delay in staff resumption","An unexpected event resulting in death or serious physical or psychological harm, or risk thereof","Shortage of gloves","Staff absenteeism"]'::jsonb, 1, 'A sentinel event is an unexpected occurrence involving death, serious physical or psychological harm, or the risk thereof.', 'Ethics, Law & Management', '⚖️', true),
(4133, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The purpose of a root cause analysis (RCA) following a sentinel event is to:', '["Identify who should be punished","Determine underlying system factors and prevent recurrence","Assign blame to the ward manager","Prepare legal charges only"]'::jsonb, 1, 'Root cause analysis after a sentinel event aims to uncover underlying system factors so recurrence can be prevented.', 'Ethics, Law & Management', '⚖️', true),
(4134, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A nurse manager notices frequent conflicts between nurses and physicians. The BEST long-term strategy is to:', '["Ignore the conflicts","Promote interprofessional communication, teamwork, and conflict-resolution training","Transfer all nurses","Restrict communication between nurses and physicians"]'::jsonb, 1, 'Structured interprofessional communication and conflict-resolution training address recurring nurse-physician conflict at its root, longer-term.', 'Ethics, Law & Management', '⚖️', true),
(4135, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A nurse manager consistently encourages staff to suggest ideas that improve patient care. This demonstrates:', '["Transactional leadership","Transformational leadership","Bureaucratic leadership","Autocratic leadership"]'::jsonb, 1, 'Actively soliciting and valuing staff ideas for improving care is a hallmark of transformational leadership.', 'Ethics, Law & Management', '⚖️', true),
(4136, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which factor is MOST important when assigning staff to an ICU shift?', '["Staff preference alone","Patient acuity and staff competence","Age of the nurse","Length of employment only"]'::jsonb, 1, 'Matching staff assignments to patient acuity and staff competence is essential for safe ICU staffing.', 'Ethics, Law & Management', '⚖️', true),
(4137, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A nurse manager receives a complaint regarding breach of patient confidentiality. The FIRST responsibility is to:', '["Dismiss the accused nurse immediately","Conduct a fair investigation while protecting patient privacy","Ignore the complaint","Discuss the case openly during ward rounds"]'::jsonb, 1, 'A fair investigation that protects patient privacy is the appropriate first response to a confidentiality breach complaint.', 'Ethics, Law & Management', '⚖️', true),
(4138, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which of the following is an example of clinical governance?', '["Conducting regular clinical audits and implementing improvements","Increasing hospital fees","Restricting patient complaints","Delegating all decisions to physicians"]'::jsonb, 0, 'Regular clinical audits with resulting improvements are a concrete example of clinical governance in action.', 'Ethics, Law & Management', '⚖️', true),
(4139, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The MOST reliable indicator of quality nursing care is:', '["Number of nurses on duty","Positive patient outcomes based on evidence-based practice","Number of hospital admissions","Quantity of equipment purchased"]'::jsonb, 1, 'Positive, evidence-based patient outcomes are the most reliable indicator of quality nursing care.', 'Ethics, Law & Management', '⚖️', true),
(4140, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which management strategy is MOST effective in preventing staff burnout in the ICU?', '["Mandatory overtime","Balanced staffing, regular breaks, and psychological support","Frequent night duties","Reduction of annual leave"]'::jsonb, 1, 'Balanced staffing, adequate breaks, and psychological support are proven strategies against ICU staff burnout.', 'Ethics, Law & Management', '⚖️', true),
(4141, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A nurse manager observes that staff members are reluctant to report medication errors due to fear of punishment. Which culture should be promoted?', '["Blame culture","Just culture","Punitive culture","Competitive culture"]'::jsonb, 1, 'A just culture, focused on system learning rather than blame, encourages honest reporting of medication errors.', 'Ethics, Law & Management', '⚖️', true),
(4142, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which document should be reviewed FIRST during a nursing quality audit?', '["Payroll register","Patient care records","Staff attendance book","Hospital inventory"]'::jsonb, 1, 'Patient care records are the primary source document reviewed first in a nursing quality audit.', 'Ethics, Law & Management', '⚖️', true),
(4143, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The MOST appropriate quality improvement project after an increase in hospital-acquired infections is to:', '["Increase admissions","Strengthen infection prevention and control practices through audit, education, and monitoring","Reduce documentation","Decrease hand hygiene audits"]'::jsonb, 1, 'A structured quality improvement project — combining audit, education, and monitoring — best addresses a rise in hospital-acquired infections.', 'Ethics, Law & Management', '⚖️', true),
(4144, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A staff nurse refuses to care for a patient because of the patient''s infectious disease diagnosis. The nurse manager should explain that:', '["Nurses may refuse any assigned patient","Professional duty requires care using appropriate infection prevention measures, unless there is a legally or ethically justified exception","Only doctors should care for infectious patients","The patient should be discharged"]'::jsonb, 1, 'Professional duty requires providing care using appropriate infection prevention precautions rather than refusing care outright.', 'Ethics, Law & Management', '⚖️', true),
(4145, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The PRIMARY purpose of accreditation in healthcare is to:', '["Increase hospital income","Ensure organizations meet recognized quality and safety standards","Reduce staff numbers","Eliminate documentation"]'::jsonb, 1, 'Accreditation exists to verify that an organisation meets recognised standards of quality and safety.', 'Ethics, Law & Management', '⚖️', true),
(4146, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which leadership quality BEST promotes trust among nursing staff?', '["Consistency, honesty, and fairness","Frequent criticism","Favoritism","Poor communication"]'::jsonb, 0, 'Consistency, honesty, and fairness are foundational to building staff trust in a leader.', 'Ethics, Law & Management', '⚖️', true),
(4147, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The overall responsibility of the nurse manager in an ICU is to:', '["Perform all nursing procedures personally","Coordinate safe, effective, evidence-based care through appropriate leadership and resource management","Supervise doctors","Manage only financial resources"]'::jsonb, 1, 'The ICU nurse manager''s overall responsibility is coordinating safe, effective, evidence-based care through leadership and resource management.', 'Ethics, Law & Management', '⚖️', true),
(4148, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The nurse manager plans to introduce a new electronic documentation system. The FIRST step should be to:', '["Implement it without informing staff","Assess readiness, communicate the change, and provide training","Punish staff who resist","Remove paper records immediately"]'::jsonb, 1, 'Assessing readiness, communicating the change, and training staff are the essential first steps before rolling out a new system.', 'Ethics, Law & Management', '⚖️', true),
(4149, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which of the following is the BEST example of evidence-based management?', '["Making decisions based only on seniority","Using research findings, organizational data, and professional expertise to guide management decisions","Following tradition regardless of outcomes","Making decisions without consulting staff"]'::jsonb, 1, 'Evidence-based management combines research evidence, organisational data, and professional expertise to guide decisions.', 'Ethics, Law & Management', '⚖️', true),
(4150, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A charge nurse notices that one nurse is caring for significantly more critically ill patients than others. What is the BEST action?', '["Leave assignments unchanged","Reassess workload and redistribute patients according to acuity and staff competence","Ask the nurse to work faster","Send the nurse home"]'::jsonb, 1, 'Redistributing patients according to acuity and staff competence directly addresses an imbalanced, unsafe workload.', 'Ethics, Law & Management', '⚖️', true),
(4151, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which management function includes coaching and motivating staff?', '["Planning","Organizing","Leading (Directing)","Budgeting"]'::jsonb, 2, 'Leading (directing) is the management function that includes coaching, motivating, and guiding staff.', 'Ethics, Law & Management', '⚖️', true),
(4152, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A nurse manager uses quality indicators such as pressure injury rates and patient falls to:', '["Increase workload","Monitor and improve quality of care","Determine salary","Reduce staffing"]'::jsonb, 1, 'Quality indicators such as pressure injury and fall rates are tracked specifically to monitor and improve care quality.', 'Ethics, Law & Management', '⚖️', true),
(4153, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'When a serious adverse event occurs, disclosure to the patient or family should be:', '["Delayed indefinitely","Honest, timely, and in accordance with institutional policy","Avoided to prevent complaints","Done only through social media"]'::jsonb, 1, 'Honest, timely disclosure in line with institutional policy is the standard for communicating serious adverse events to patients/families.', 'Ethics, Law & Management', '⚖️', true),
(4154, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which of the following BEST describes delegation?', '["Transferring accountability to another person","Assigning responsibility and authority while retaining accountability","Asking another nurse to perform all your duties","Avoiding difficult tasks"]'::jsonb, 1, 'Delegation means assigning responsibility and authority for a task while the delegator retains ultimate accountability.', 'Ethics, Law & Management', '⚖️', true),
(4155, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A nurse manager is reviewing an increase in staff absenteeism. Which action is MOST appropriate?', '["Ignore the trend","Analyze causes, meet with staff, and develop supportive interventions","Dismiss all absent staff","Cancel annual leave"]'::jsonb, 1, 'Analysing causes and engaging supportively with staff addresses the underlying drivers of rising absenteeism.', 'Ethics, Law & Management', '⚖️', true),
(4156, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The MOST effective method of reducing medication errors is to:', '["Rely on memory","Standardize medication processes, encourage reporting, and provide ongoing education","Eliminate documentation","Increase patient turnover"]'::jsonb, 1, 'Standardising processes, encouraging reporting, and ongoing education together address medication error risk systemically.', 'Ethics, Law & Management', '⚖️', true),
(4157, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which ethical principle is demonstrated by respecting a competent patient''s informed refusal of treatment?', '["Beneficence","Justice","Autonomy","Fidelity"]'::jsonb, 2, 'Respecting a competent patient''s informed refusal of treatment reflects the ethical principle of autonomy.', 'Ethics, Law & Management', '⚖️', true),
(4158, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A nurse manager evaluating a new policy should primarily consider:', '["Its impact on patient safety, quality of care, and staff performance","Personal preference","Cost only","Popular opinion"]'::jsonb, 0, 'New policies should be evaluated primarily by their impact on patient safety, care quality, and staff performance.', 'Ethics, Law & Management', '⚖️', true),
(4159, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The BEST method for maintaining staff competence is:', '["Annual punishment","Continuing professional development and competency assessment","Ignoring training needs","Reducing supervision"]'::jsonb, 1, 'Continuing professional development combined with competency assessment maintains staff skill over time.', 'Ethics, Law & Management', '⚖️', true),
(4160, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which communication technique is MOST effective during patient handover?', '["Informal conversation","Structured communication (e.g., SBAR)","Text messages only","Verbal report without documentation"]'::jsonb, 1, 'SBAR (Situation-Background-Assessment-Recommendation) is a structured communication technique proven effective for handovers.', 'Ethics, Law & Management', '⚖️', true),
(4161, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A nurse manager conducting a performance appraisal should:', '["Base the evaluation on objective evidence and agreed performance standards","Evaluate according to friendship","Focus only on mistakes","Compare staff without criteria"]'::jsonb, 0, 'Performance appraisal should be grounded in objective evidence measured against agreed standards.', 'Ethics, Law & Management', '⚖️', true),
(4162, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The PRIMARY purpose of mentorship in nursing is to:', '["Increase workload","Support professional growth and competence","Replace supervision","Assess salary"]'::jsonb, 1, 'Mentorship exists primarily to support a nurse''s professional growth and development of competence.', 'Ethics, Law & Management', '⚖️', true),
(4163, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'In disaster management, the nurse manager''s priority is to:', '["Continue routine ward activities","Coordinate safe, efficient care using available resources according to the disaster plan","Suspend all admissions permanently","Close the hospital"]'::jsonb, 1, 'In disaster management, the nurse manager''s priority is coordinating safe, efficient care within the established disaster plan and available resources.', 'Ethics, Law & Management', '⚖️', true),
(4164, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which strategy BEST supports patient-centered care?', '["Making decisions without patient involvement","Involving patients and families in care planning whenever appropriate","Limiting communication","Ignoring patient preferences"]'::jsonb, 1, 'Involving patients and families in care planning is central to patient-centered care.', 'Ethics, Law & Management', '⚖️', true),
(4165, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A manager who recognizes staff achievements and encourages innovation is likely to improve:', '["Staff motivation and retention","Medication costs","Equipment depreciation","Administrative delays"]'::jsonb, 0, 'Recognising achievement and encouraging innovation boosts staff motivation and, in turn, retention.', 'Ethics, Law & Management', '⚖️', true),
(4166, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The nurse manager''s role in infection prevention includes:', '["Ensuring compliance with infection prevention policies, surveillance, education, and appropriate use of PPE","Delegating all responsibility to cleaners","Focusing only on environmental cleaning","Reporting infections only at year-end"]'::jsonb, 0, 'Ensuring policy compliance, surveillance, education, and appropriate PPE use are core nurse manager responsibilities in infection prevention.', 'Ethics, Law & Management', '⚖️', true),
(4167, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The hallmark of an effective nurse manager is the ability to:', '["Control every task personally","Lead teams to deliver safe, ethical, high-quality, evidence-based patient care while using resources effectively","Avoid delegation","Make decisions without consultation"]'::jsonb, 1, 'An effective nurse manager''s hallmark is leading teams to deliver safe, ethical, evidence-based care while using resources effectively.', 'Ethics, Law & Management', '⚖️', true),
(4168, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A newly qualified ICU nurse administers a high-alert medication without following the independent double-check policy. The patient is unharmed. The nurse manager''s BEST action is to:', '["Dismiss the nurse immediately","Reinforce the policy, document the incident, and provide competency-based education","Ignore the incident because no harm occurred","Publicly reprimand the nurse"]'::jsonb, 1, 'Reinforcing the double-check policy, documenting, and providing targeted education addresses both the immediate lapse and future prevention.', 'Ethics, Law & Management', '⚖️', true),
(4169, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The MOST effective indicator that a quality improvement initiative has been successful is:', '["Increased staff meetings","Improved patient outcomes and sustained compliance with standards","Increased documentation only","Reduced reporting of incidents"]'::jsonb, 1, 'Sustained improvement in outcomes and continued adherence to standards is the clearest sign a quality initiative has succeeded.', 'Ethics, Law & Management', '⚖️', true),
(4170, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A nurse manager notices repeated stock-outs of emergency drugs in the ICU. The PRIORITY management action is to:', '["Borrow drugs from another ward without documentation","Review inventory management processes, determine the cause, and implement corrective measures","Wait until the next budget cycle","Blame the pharmacy department"]'::jsonb, 1, 'Reviewing inventory processes and identifying the root cause addresses repeated emergency drug stock-outs systematically.', 'Ethics, Law & Management', '⚖️', true),
(4171, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which of the following best demonstrates professional accountability?', '["Delegating all responsibilities to junior staff","Accepting responsibility for one''s actions and maintaining professional standards","Avoiding difficult patients","Working only under supervision"]'::jsonb, 1, 'Professional accountability means accepting responsibility for one''s actions and upholding professional standards.', 'Ethics, Law & Management', '⚖️', true),
(4172, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A patient refuses a blood transfusion after receiving adequate information and demonstrating decision-making capacity. The nurse should:', '["Force the patient to accept treatment","Respect the patient''s informed decision, document it, and inform the healthcare team","Obtain consent from another patient","Ignore the refusal"]'::jsonb, 1, 'A capacitated patient''s informed refusal must be respected, documented, and communicated to the care team.', 'Ethics, Law & Management', '⚖️', true),
(4173, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The PRIMARY purpose of clinical supervision is to:', '["Punish staff","Support safe practice, professional development, and quality patient care","Increase documentation only","Reduce staff independence"]'::jsonb, 1, 'Clinical supervision exists to support safe practice, professional growth, and quality patient care.', 'Ethics, Law & Management', '⚖️', true),
(4174, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A nurse manager reviewing incident reports notices a trend in patient falls. The NEXT step after identifying the trend is to:', '["Ignore the reports","Develop and implement a fall-prevention improvement plan and monitor outcomes","Punish all nurses","Stop reporting falls"]'::jsonb, 1, 'Identifying a trend should be followed by developing and implementing a targeted improvement plan with ongoing monitoring — here, for falls.', 'Ethics, Law & Management', '⚖️', true),
(4175, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which of the following BEST reflects the principle of justice in nursing ethics?', '["Respecting a patient''s right to refuse treatment","Treating patients fairly and without discrimination","Keeping patient information confidential","Telling the truth to patients"]'::jsonb, 1, 'Treating patients fairly and without discrimination reflects the ethical principle of justice.', 'Ethics, Law & Management', '⚖️', true),
(4176, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The MOST appropriate leadership approach during a sudden cardiac arrest in the ICU is:', '["Laissez-faire leadership","Autocratic leadership with clear, direct instructions","Democratic leadership by voting on interventions","Bureaucratic leadership without communication"]'::jsonb, 1, 'Clear, direct, autocratic leadership suits the urgency of a cardiac arrest response.', 'Ethics, Law & Management', '⚖️', true),
(4177, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A nurse manager is planning continuing education for staff. Which method is MOST likely to improve competency?', '["Reading policies without discussion","Simulation-based training combined with skills assessment","Distributing memos only","Asking staff to learn independently"]'::jsonb, 1, 'Simulation-based training paired with skills assessment is a highly effective method for building and verifying competency.', 'Ethics, Law & Management', '⚖️', true),
(4178, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which of the following is a key responsibility of a nurse manager during disaster preparedness?', '["Develop, communicate, and regularly evaluate disaster response plans","Close the hospital permanently","Cancel emergency drills","Delegate all planning to external agencies"]'::jsonb, 0, 'Developing, communicating, and regularly evaluating disaster plans is a core nurse manager responsibility in disaster preparedness.', 'Ethics, Law & Management', '⚖️', true),
(4179, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A nurse manager receives reports of workplace bullying. The MOST appropriate initial response is to:', '["Ignore the reports","Promptly investigate, ensure staff safety, and address the issue according to policy","Transfer the complainant only","Assume the reports are false"]'::jsonb, 1, 'Workplace bullying reports require a prompt investigation, ensuring staff safety, handled per institutional policy.', 'Ethics, Law & Management', '⚖️', true),
(4180, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which quality improvement model follows the sequence Plan–Do–Study–Act (PDSA)?', '["Continuous quality improvement cycle","SWOT analysis","Maslow''s hierarchy","Fayol''s management process"]'::jsonb, 0, 'The Plan-Do-Study-Act (PDSA) cycle underlies the continuous quality improvement approach.', 'Ethics, Law & Management', '⚖️', true),
(4181, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The MOST effective strategy for reducing hospital-acquired infections is:', '["Routine antibiotic use for all patients","Strict adherence to infection prevention and control practices, including hand hygiene","Limiting patient admissions","Reducing environmental cleaning"]'::jsonb, 1, 'Strict infection prevention and control adherence, especially hand hygiene, is the most effective strategy against hospital-acquired infections.', 'Ethics, Law & Management', '⚖️', true),
(4182, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which characteristic BEST describes a transformational nurse leader?', '["Relies mainly on punishment","Inspires, motivates, and empowers staff to achieve shared goals","Avoids change","Makes all decisions without consultation"]'::jsonb, 1, 'A transformational leader inspires, motivates, and empowers staff toward shared goals.', 'Ethics, Law & Management', '⚖️', true),
(4183, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A nurse manager delegates the measurement of vital signs of a stable patient to a nursing assistant. Before delegation, the manager should ensure that the assistant:', '["Is willing to perform the task only","Is competent, authorized, and understands when to report abnormal findings","Has worked for many years","Has no other assigned duties"]'::jsonb, 1, 'Before delegating vital signs measurement, the manager must confirm the assistant is competent, authorised, and knows when to escalate abnormal findings.', 'Ethics, Law & Management', '⚖️', true),
(4184, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'The PRIMARY objective of performance appraisal is to:', '["Identify staff for dismissal","Improve performance, recognize achievements, and identify learning needs","Reduce salaries","Compare employees without standards"]'::jsonb, 1, 'Performance appraisal''s primary purpose is to improve performance, recognise achievement, and identify learning needs.', 'Ethics, Law & Management', '⚖️', true),
(4185, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A nurse manager discovers that confidential patient information has been shared on social media by a staff member. The MOST appropriate action is to:', '["Ignore the incident","Follow institutional disciplinary procedures, protect the patient''s rights, and reinforce confidentiality policies","Delete the post without investigation","Ask another nurse to apologize"]'::jsonb, 1, 'A confidentiality breach on social media requires disciplinary process, protection of patient rights, and reinforcement of policy.', 'Ethics, Law & Management', '⚖️', true),
(4186, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'Which statement BEST describes evidence-based nursing management?', '["Decisions are based solely on experience","Management decisions integrate current research evidence, clinical expertise, organizational data, and patient safety principles","Policies never require review","Decisions are based on seniority"]'::jsonb, 1, 'Evidence-based nursing management integrates research evidence, clinical expertise, organisational data, and patient safety principles.', 'Ethics, Law & Management', '⚖️', true),
(4187, 'Nursing Management', 'NMCN Management MCQs (class study document)', 'A competent nurse manager is BEST described as one who:', '["Performs every task personally","Effectively plans, organizes, leads, coordinates, and evaluates nursing services while ensuring safe, ethical, patient-centered, evidence-based care and efficient resource utilization","Focuses only on administrative duties","Delegates all responsibilities without supervision"]'::jsonb, 1, 'A competent nurse manager effectively plans, organizes, leads, coordinates, and evaluates services while ensuring safe, ethical, evidence-based, resource-efficient care.', 'Ethics, Law & Management', '⚖️', true),
(4188, 'Spinal Cord & Neuromuscular Disorders', 'Spinal Cord Disorders MCQs (class study document)', 'Which of the following diseases is caused by the poliovirus?', '["Tetanus","Poliomyelitis","Guillain-Barré syndrome","Polyneuritis"]'::jsonb, 1, 'Poliomyelitis is the disease caused by infection with poliovirus, which attacks motor neurons in the spinal cord.', 'Neurology', '🧠', true),
(4189, 'Spinal Cord & Neuromuscular Disorders', 'Spinal Cord Disorders MCQs (class study document)', 'What is the primary treatment for Guillain-Barré syndrome?', '["Antibiotics","Physical therapy","Chemotherapy","Surgery"]'::jsonb, 1, 'Among the given choices, physical therapy best supports recovery of strength and function after the acute phase of Guillain-Barré syndrome, alongside definitive treatments like IVIG or plasmapheresis in acute management.', 'Neurology', '🧠', true),
(4190, 'Spinal Cord & Neuromuscular Disorders', 'Spinal Cord Disorders MCQs (class study document)', 'Which of the following statements about polyneuritis is true?', '["It is a rare condition with no known cause","Symptoms typically improve on their own without treatment","Treatment may include corticosteroids and immunosuppressive drugs","Polyneuritis is caused by exposure to contaminated water"]'::jsonb, 2, 'Polyneuritis (inflammation of multiple peripheral nerves) may be managed with corticosteroids and immunosuppressive therapy when an underlying inflammatory or autoimmune cause is identified.', 'Neurology', '🧠', true),
(4191, 'Spinal Cord & Neuromuscular Disorders', 'Spinal Cord Disorders MCQs (class study document)', 'How is the diagnosis of polyneuritis typically made?', '["Blood tests","MRI","Nerve conduction studies","Physical examination"]'::jsonb, 2, 'Nerve conduction studies assess the speed and strength of electrical signals in peripheral nerves, helping confirm a diagnosis of polyneuritis.', 'Neurology', '🧠', true),
(4192, 'Spinal Cord & Neuromuscular Disorders', 'Spinal Cord Disorders MCQs (class study document)', 'What is the recommended treatment for someone who has not been vaccinated against tetanus and experiences a puncture wound?', '["Antibiotics","Painkillers","Tetanus immunoglobulin and vaccination","Rest and hydration"]'::jsonb, 2, 'For an unvaccinated or incompletely immunised patient with a puncture wound, both tetanus immunoglobulin (passive immunity) and vaccine (active immunity) are recommended.', 'Neurology', '🧠', true),
(4193, 'Spinal Cord & Neuromuscular Disorders', 'Spinal Cord Disorders MCQs (class study document)', 'What is the primary method for preventing the spread of poliovirus in communities?', '["Wearing masks","Handwashing","Avoiding public gatherings","Quarantining infected individuals"]'::jsonb, 1, 'Hand hygiene, alongside vaccination, is a key public health measure for interrupting the faecal-oral spread of poliovirus in communities.', 'Neurology', '🧠', true),
(4194, 'Spinal Cord & Neuromuscular Disorders', 'Spinal Cord Disorders MCQs (class study document)', 'What is the recommended time frame for receiving a tetanus booster following an injury?', '["1-2 weeks","1 month","3 months","10 years"]'::jsonb, 3, 'Tetanus booster vaccination is generally recommended every 10 years, or sooner after a high-risk/contaminated wound if the last dose was more than 5 years prior.', 'Neurology', '🧠', true),
(4195, 'Electrolyte Imbalances and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with heart failure and severe hyponatremia (Na⁺ 115 mEq/L) develops seizures. Which intervention should the nurse initiate FIRST?', '["Administer 3% hypertonic saline IV","Restrict oral fluid intake to 500 mL/day","Give furosemide 40 mg IV","Start oral sodium chloride tablets"]'::jsonb, 0, 'Severe symptomatic hyponatremia (e.g., seizures) requires rapid correction with 3% hypertonic saline to prevent cerebral edema and herniation. Fluid restriction and diuretics are adjunctive but not immediate for life-threatening symptoms.', 'ABG & Electrolytes', '🩸', true),
(4196, 'Electrolyte Imbalances and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with end-stage renal disease has a serum K⁺ of 6.8 mEq/L and ECG shows widened QRS complexes. Which intervention is MOST urgent?', '["Administer sodium polystyrene sulfonate orally","Infuse 10 units of regular insulin IV with 50% dextrose","Give calcium gluconate 10% IV","Initiate hemodialysis"]'::jsonb, 2, 'Calcium gluconate stabilizes cardiac membranes to prevent arrhythmias from hyperkalemia. Insulin/dextrose shifts K⁺ intracellularly but does not address imminent cardiac risk. Dialysis is definitive but slower.', 'ABG & Electrolytes', '🩸', true),
(4197, 'Electrolyte Imbalances and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A postoperative patient with hypocalcemia (ionized Ca²⁺ 0.8 mmol/L) exhibits carpopedal spasm and laryngeal stridor. Which action takes priority?', '["Administer oral calcium carbonate","Give vitamin D supplements","Infuse 10% calcium gluconate IV","Apply a nasal cannula at 2 L/min"]'::jsonb, 2, 'IV calcium gluconate is critical for acute, symptomatic hypocalcemia to reverse neuromuscular irritability and prevent respiratory arrest.', 'ABG & Electrolytes', '🩸', true),
(4198, 'Electrolyte Imbalances and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with hypermagnesemia (Mg²⁺ 4.5 mg/dL) has hypotension and absent deep tendon reflexes. Which intervention is MOST appropriate?', '["Administer magnesium sulfate IV","Infuse 0.9% normal saline bolus","Give calcium chloride 10% IV","Start furosemide 40 mg IV"]'::jsonb, 2, 'Calcium antagonizes magnesium’s effects on neuromuscular and cardiovascular systems. Saline boluses and diuretics support excretion but do not directly counteract toxicity.', 'ABG & Electrolytes', '🩸', true),
(4199, 'Electrolyte Imbalances and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'In a patient with hypophosphatemia (PO₄²⁻ 1.0 mg/dL), which complication should the nurse anticipate?', '["Hypertension and edema","Muscle weakness and respiratory failure","Tetany and positive Trousseau’s sign","Polyuria and polydipsia"]'::jsonb, 1, 'Severe hypophosphatemia impairs ATP production, leading to diaphragmatic weakness, respiratory failure, and cardiac dysfunction.', 'ABG & Electrolytes', '🩸', true),
(4200, 'Electrolyte Imbalances and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with SIADH has serum Na⁺ 120 mEq/L and urine osmolality 600 mOsm/kg. Which intervention is indicated?', '["Free water bolus IV","Fluid restriction to 800 mL/day","Administer desmopressin","Start 0.9% saline at 150 mL/hr"]'::jsonb, 1, 'SIADH causes water retention and dilutional hyponatremia. Fluid restriction is first-line therapy; IV saline may worsen hyponatremia if not hypertonic.', 'ABG & Electrolytes', '🩸', true),
(4201, 'Electrolyte Imbalances and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with diabetic ketoacidosis has K⁺ 5.2 mEq/L before insulin therapy. After starting insulin, which K⁺ level indicates effective treatment?', '["5.0 mEq/L","4.8 mEq/L","3.9 mEq/L","3.2 mEq/L"]'::jsonb, 3, 'Insulin drives K⁺ into cells, causing hypokalemia. A drop to 3.2 mEq/L reflects successful intracellular shift but requires replacement to prevent arrhythmias.', 'ABG & Electrolytes', '🩸', true),
(4202, 'Electrolyte Imbalances and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with hypercalcemia (Ca²⁺ 13.5 mg/dL) has ECG changes. Which finding is expected?', '["Peaked T waves","Prolonged QT interval","Shortened QT interval","U waves"]'::jsonb, 2, 'Hypercalcemia shortens the QT interval due to accelerated ventricular repolarization. Peaked T waves occur in hyperkalemia; prolonged QT/U waves in hypokalemia.', 'ABG & Electrolytes', '🩸', true),
(4203, 'Electrolyte Imbalances and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with hypokalemia (K⁺ 2.8 mEq/L) is receiving IV potassium. Which nursing action is essential?', '["Infuse at 20 mEq/hr via central line","Monitor serum K⁺ every 2 hours","Administer as an IV bolus","Dilute in 50 mL D5W over 10 minutes"]'::jsonb, 1, 'Frequent serum K⁺ monitoring prevents overcorrection and hyperkalemia. IV potassium must be diluted and infused slowly (max 10 mEq/hr peripherally).', 'ABG & Electrolytes', '🩸', true),
(4204, 'Electrolyte Imbalances and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with metabolic acidosis has K⁺ 5.8 mEq/L. Which intervention addresses BOTH imbalances?', '["Administer sodium bicarbonate IV","Give calcium gluconate IV","Start kayexalate orally","Infuse regular insulin IV"]'::jsonb, 0, 'Sodium bicarbonate corrects acidosis and shifts K⁺ intracellularly. Insulin also shifts K⁺ but does not correct acidosis.', 'ABG & Electrolytes', '🩸', true),
(4205, 'Electrolyte Imbalances and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'In a patient with hyperkalemia, which ECG change warrants IMMEDIATE intervention?', '["ST-segment depression","Peaked T waves","Sinus tachycardia","First-degree AV block"]'::jsonb, 1, 'Peaked T waves are an early sign of hyperkalemia and may progress to life-threatening arrhythmias.', 'ABG & Electrolytes', '🩸', true),
(4206, 'Electrolyte Imbalances and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with hypomagnesemia (Mg²⁺ 1.2 mg/dL) has refractory hypokalemia. Which intervention is MOST effective?', '["Increase oral K⁺ supplements","Administer IV magnesium sulfate","Start spironolactone","Infuse calcium gluconate"]'::jsonb, 1, 'Hypomagnesemia impairs K⁺ repletion; magnesium must be corrected first.', 'ABG & Electrolytes', '🩸', true),
(4207, 'Electrolyte Imbalances and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with hyponatremia is receiving hypertonic saline. Which sign indicates osmotic demyelination syndrome?', '["Seizures","Dysarthria and quadriparesis","Polyuria","Hypertension"]'::jsonb, 1, 'Rapid correction of hyponatremia can cause central pontine myelinolysis, leading to irreversible neurological deficits (e.g., dysarthria, paralysis).', 'ABG & Electrolytes', '🩸', true),
(4208, 'Electrolyte Imbalances and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with hyperphosphatemia (PO₄³⁻ 7.0 mg/dL) is at risk for which electrolyte imbalance?', '["Hypercalcemia","Hypocalcemia","Hypernatremia","Hypermagnesemia"]'::jsonb, 1, 'Hyperphosphatemia binds calcium, leading to hypocalcemia and tetany.', 'ABG & Electrolytes', '🩸', true),
(4209, 'Electrolyte Imbalances and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with hypochloremia (Cl⁻ 88 mEq/L) and metabolic alkalosis should receive:', '["0.45% saline IV","Acetazolamide","Potassium supplements","Ammonium chloride"]'::jsonb, 0, 'Hypochloremic metabolic alkalosis (e.g., from vomiting) responds to chloride-rich fluids (e.g., 0.9% or 0.45% saline).', 'ABG & Electrolytes', '🩸', true),
(4210, 'Electrolyte Imbalances and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with hypernatremia (Na⁺ 160 mEq/L) is lethargic. Which fluid should the nurse administer?', '["3% saline","0.9% saline","D5W","Lactated Ringer’s"]'::jsonb, 2, 'Hypernatremia requires free water (e.g., D5W) to correct hypertonicity. Saline solutions worsen hypernatremia.', 'ABG & Electrolytes', '🩸', true),
(4211, 'Electrolyte Imbalances and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with hypokalemia has U waves on ECG. Which drug increases the risk of this finding?', '["Furosemide","Spironolactone","Amlodipine","Metoprolol"]'::jsonb, 0, 'Loop diuretics (e.g., furosemide) cause renal K⁺ loss. U waves are a hallmark of hypokalemia.', 'ABG & Electrolytes', '🩸', true),
(4212, 'Electrolyte Imbalances and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with hypercalcemia is prescribed calcitonin. The nurse should monitor for:', '["Hypoglycemia","Hyperphosphatemia","Hypocalcemia","Tachyphylaxis"]'::jsonb, 3, 'Calcitonin loses efficacy after 48 hours (tachyphylaxis). Hypocalcemia is rare; it primarily lowers calcium.', 'ABG & Electrolytes', '🩸', true),
(4213, 'Electrolyte Imbalances and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with hypophosphatemia is receiving TPN. Which intervention prevents refeeding syndrome?', '["Start TPN at full calories","Supplement with IV phosphorus","Restrict glucose in TPN","Add extra potassium"]'::jsonb, 1, 'Refeeding syndrome causes hypophosphatemia; preemptive supplementation and gradual calorie increase are key.', 'ABG & Electrolytes', '🩸', true),
(4214, 'Electrolyte Imbalances and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with hyperkalemia has peaked T waves. After calcium gluconate, which drug shifts potassium intracellularly?', '["Albuterol","Sodium polystyrene","Furosemide","Fludrocortisone"]'::jsonb, 0, 'Albuterol (\beta2-agonist) shifts K⁺ into cells. Sodium polystyrene increases excretion but is slow-acting.', 'ABG & Electrolytes', '🩸', true),
(4215, 'Pharmacology in Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient in septic shock requires norepinephrine. Which effect is PRIMARY for this drug?', '["Increased myocardial contractility","Vasoconstriction","Bronchodilation","Renal artery dilation"]'::jsonb, 1, 'Norepinephrine is an \alpha-agonist that increases SVR and MAP in septic shock. Inotropy is secondary.', 'ICU Pharmacology', '💊', true),
(4216, 'Pharmacology in Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient on a propofol infusion develops metabolic acidosis and rhabdomyolysis. The nurse suspects:', '["Anaphylaxis","Propofol infusion syndrome","Serotonin syndrome","Malignant hyperthermia"]'::jsonb, 1, 'PRIS is a rare but fatal complication of propofol, characterized by lactic acidosis, rhabdomyolysis, and cardiac failure.', 'ICU Pharmacology', '💊', true),
(4217, 'Pharmacology in Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient receiving IV heparin has an aPTT of 110 seconds. Which reversal agent should be available?', '["Vitamin K","Protamine sulfate","Idarucizumab","Andexanet alfa"]'::jsonb, 1, 'Protamine sulfate reverses heparin. Vitamin K is for warfarin; idarucizumab/andexanet for DOACs.', 'ICU Pharmacology', '💊', true),
(4218, 'Pharmacology in Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient on fentanyl PCA has a respiratory rate of 8/min and is somnolent. Which antidote should the nurse administer?', '["Flumazenil","Naloxone","Physostigmine","Romazicon"]'::jsonb, 1, 'Naloxone reverses opioid-induced respiratory depression. Flumazenil reverses benzodiazepines.', 'ICU Pharmacology', '💊', true),
(4219, 'Pharmacology in Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient receiving vancomycin has flushing, rash, and hypotension. Which action is BEST?', '["Stop infusion and administer diphenhydramine","Increase infusion rate to complete dose","Switch to oral vancomycin","Administer epinephrine"]'::jsonb, 0, 'Red man syndrome is a histamine-mediated reaction. Stopping the infusion and giving antihistamines is standard.', 'ICU Pharmacology', '💊', true),
(4220, 'Pharmacology in Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with atrial fibrillation is started on amiodarone. The nurse should monitor for:', '["Pulmonary fibrosis","Hypertension","Hypoglycemia","Diarrhea"]'::jsonb, 0, 'Amiodarone can cause pulmonary fibrosis, thyroid dysfunction, and liver toxicity.', 'ICU Pharmacology', '💊', true),
(4221, 'Pharmacology in Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with status epilepticus is receiving midazolam. Which reversal agent is on standby?', '["Naloxone","Flumazenil","Protamine","Glucagon"]'::jsonb, 1, 'Flumazenil reverses benzodiazepines like midazolam.', 'ICU Pharmacology', '💊', true),
(4222, 'Pharmacology in Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient on dopamine at 15 mcg/kg/min is likely to experience:', '["Renal artery dilation","Vasoconstriction","Bronchospasm","Hyperglycemia"]'::jsonb, 1, 'High-dose dopamine ($>$10 mcg/kg/min) activates \alpha-receptors, causing vasoconstriction.', 'ICU Pharmacology', '💊', true),
(4223, 'Pharmacology in Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with septic shock is started on vasopressin. Which effect is expected?', '["Decreased SVR","Increased urine output","Coronary vasodilation","Vasoconstriction"]'::jsonb, 3, 'Vasopressin is a potent vasoconstrictor used in refractory septic shock.', 'ICU Pharmacology', '💊', true),
(4224, 'Pharmacology in Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient receiving succinylcholine develops hyperkalemia. Which condition predisposes to this?', '["Asthma","Parkinson’s disease","Guillain-Barré syndrome","Migraine"]'::jsonb, 2, 'Succinylcholine causes K⁺ release in denervating conditions (e.g., GBS, burns, trauma).', 'ICU Pharmacology', '💊', true),
(4225, 'Pharmacology in Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient on IV nitroglycerin has a headache. Which action is BEST?', '["Administer PRN acetaminophen","Hold the next dose","Switch to oral nitrates","Increase the infusion rate"]'::jsonb, 0, 'Headache is a common side effect of nitrates. Acetaminophen is appropriate; tolerance develops over time.', 'ICU Pharmacology', '💊', true),
(4226, 'Pharmacology in Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient receiving dexmedetomidine for sedation may experience:', '["Hypertension and tachycardia","Respiratory depression","Bradycardia and hypotension","Agitation"]'::jsonb, 2, 'Dexmedetomidine (\alpha2-agonist) causes sympatholysis, leading to bradycardia/hypotension.', 'ICU Pharmacology', '💊', true),
(4227, 'Pharmacology in Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient on warfarin has an INR of 8.0. Which reversal agent is used for active bleeding?', '["Vitamin K IV","Protamine sulfate","FFP","Andexanet alfa"]'::jsonb, 2, 'FFP provides immediate clotting factors for warfarin reversal. Vitamin K works slowly.', 'ICU Pharmacology', '💊', true),
(4228, 'Pharmacology in Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with myasthenia gravis is prescribed neostigmine. The nurse should monitor for:', '["Cholinergic crisis","Neuroleptic malignant syndrome","Thyroid storm","Serotonin syndrome"]'::jsonb, 0, 'Overdose of acetylcholinesterase inhibitors (e.g., neostigmine) causes cholinergic crisis (SLUDGE syndrome).', 'ICU Pharmacology', '💊', true),
(4229, 'Pharmacology in Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient receiving IV insulin for hyperglycemia should be monitored for:', '["Hypokalemia","Hypernatremia","Hypocalcemia","Hypermagnesemia"]'::jsonb, 0, 'Insulin shifts K⁺ intracellularly, causing hypokalemia.', 'ICU Pharmacology', '💊', true),
(4230, 'Pharmacology in Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with Torsades de Pointes is prescribed magnesium sulfate. Which ECG change confirms efficacy?', '["Resolution of U waves","Narrowed QRS complex","Shortened QT interval","Absent P waves"]'::jsonb, 2, 'Magnesium shortens the QT interval, treating Torsades. U waves are associated with hypokalemia.', 'ICU Pharmacology', '💊', true),
(4231, 'Pharmacology in Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient on a \beta-blocker has hypoglycemia. Which sign may be masked?', '["Diaphoresis","Tachycardia","Tremors","Hunger"]'::jsonb, 1, '\beta-blockers blunt tachycardia (adrenergic response) in hypoglycemia.', 'ICU Pharmacology', '💊', true),
(4232, 'Pharmacology in Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient receiving cyclosporine post-transplant has hypertension. Which drug is CONTRAINDICATED?', '["Amlodipine","Nifedipine","Verapamil","Lisinopril"]'::jsonb, 2, 'Verapamil increases cyclosporine levels via CYP3A4 inhibition, risking toxicity.', 'ICU Pharmacology', '💊', true),
(4233, 'Pharmacology in Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient on high-dose corticosteroids is at risk for:', '["Hyperkalemia","Hypoglycemia","Adrenal suppression","Hypothyroidism"]'::jsonb, 2, 'Chronic steroids suppress the HPA axis, requiring stress-dose coverage.', 'ICU Pharmacology', '💊', true),
(4234, 'Pharmacology in Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with opioid overdose has respiratory depression. Naloxone is administered but wears off in 30 minutes. Which action is BEST?', '["Switch to naltrexone","Give a second naloxone dose","Start flumazenil","Intubate the patient"]'::jsonb, 1, 'Naloxone has a short half-life; redosing is needed for long-acting opioids (e.g., methadone).', 'ICU Pharmacology', '💊', true),
(4235, 'End-of-Life Care and Ethical Considerations', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with advanced cancer requests discontinuation of chemotherapy. The nurse supports this decision based on:', '["Autonomy","Beneficence","Nonmaleficence","Justice"]'::jsonb, 0, 'Autonomy respects the patient''s right to self-determination.', 'Ethics, Law & Management', '⚖️', true),
(4236, 'End-of-Life Care and Ethical Considerations', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A family disagrees with a DNR order for a patient with metastatic lung cancer. The nurse involves:', '["Ethics committee","Hospital security","Risk management","Social services"]'::jsonb, 0, 'An ethics committee helps resolve conflicts about goals of care.', 'Ethics, Law & Management', '⚖️', true),
(4237, 'End-of-Life Care and Ethical Considerations', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient is declared brain dead. Which finding confirms this diagnosis?', '["Absent brainstem reflexes","Flat EEG for 24 hours","Apnea during hypercapnia","All of the above"]'::jsonb, 3, 'Brain death requires absent brainstem reflexes, apnea, and irreversible coma.', 'Ethics, Law & Management', '⚖️', true),
(4238, 'End-of-Life Care and Ethical Considerations', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with a terminal illness has uncontrolled pain. Palliative sedation is considered when:', '["Pain is refractory to standard treatments","The family requests it","Death is imminent","The patient has depression"]'::jsonb, 0, 'Palliative sedation is for refractory symptoms, not convenience or depression.', 'Ethics, Law & Management', '⚖️', true),
(4239, 'End-of-Life Care and Ethical Considerations', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient’s advance directive states no intubation. During respiratory arrest, the nurse should:', '["Intubate emergently","Follow the advance directive","Ask family for consent","Start non-invasive ventilation"]'::jsonb, 1, 'Advance directives are legally binding; providers must honor them.', 'Ethics, Law & Management', '⚖️', true),
(4240, 'End-of-Life Care and Ethical Considerations', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient is transitioning to hospice care. The nurse explains this focuses on:', '["Curative treatment","Palliation and comfort","Life-prolonging therapies","Aggressive resuscitation"]'::jsonb, 1, 'Hospice prioritizes comfort, symptom management, and quality of life.', 'Ethics, Law & Management', '⚖️', true),
(4241, 'End-of-Life Care and Ethical Considerations', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A dying patient has Cheyne-Stokes respirations. The nurse educates the family that this is:', '["A sign of pain","Indicative of fluid overload","Normal at end-of-life","Reversible with oxygen"]'::jsonb, 2, 'Cheyne-Stokes respirations are common in dying patients and do not require intervention.', 'Ethics, Law & Management', '⚖️', true),
(4242, 'End-of-Life Care and Ethical Considerations', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with end-stage COPD desires to die at home. The nurse coordinates with:', '["Hospice team","Physical therapy","Dietary services","Cardiac rehab"]'::jsonb, 0, 'Hospice provides home-based palliative care for terminally ill patients.', 'Ethics, Law & Management', '⚖️', true),
(4243, 'End-of-Life Care and Ethical Considerations', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient’s family asks about autopsy after death. The nurse states:', '["\"Autopsy is mandatory.\"","\"Autopsy requires consent.\"","\"Autopsy is only for forensic cases.\"","\"Autopsy is unnecessary.\""]'::jsonb, 1, 'Autopsy requires informed consent from next of kin.', 'Ethics, Law & Management', '⚖️', true),
(4244, 'End-of-Life Care and Ethical Considerations', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with a DNR order develops cardiac arrest. The nurse should:', '["Start CPR","Withhold resuscitation","Call a code blue","Administer epinephrine"]'::jsonb, 1, 'DNR orders prohibit resuscitation efforts during cardiac arrest.', 'Ethics, Law & Management', '⚖️', true),
(4245, 'End-of-Life Care and Ethical Considerations', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with brain death is a potential organ donor. The nurse ensures:', '["Cessation of vasopressors","Withdrawal of life support","Maintenance of hemodynamic stability","Family presence during testing"]'::jsonb, 2, 'Organ perfusion must be maintained for viable donation.', 'Ethics, Law & Management', '⚖️', true),
(4246, 'End-of-Life Care and Ethical Considerations', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A family member is distressed by a dying patient’s agitation. Non-pharmacologic interventions include:', '["Restraints","Soft music and dim lighting","Frequent vital signs","High-protein diet"]'::jsonb, 1, 'Calm environments reduce agitation; restraints increase distress.', 'Ethics, Law & Management', '⚖️', true),
(4247, 'End-of-Life Care and Ethical Considerations', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient’s living will specifies no feeding tubes. During a stroke, the nurse honors this by:', '["Inserting an NG tube","Initiating TPN","Providing oral comfort feeds","Withholding all nutrition"]'::jsonb, 2, 'Comfort feeds (e.g., ice chips) respect autonomy while avoiding artificial nutrition.', 'Ethics, Law & Management', '⚖️', true),
(4248, 'End-of-Life Care and Ethical Considerations', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A nurse experiences moral distress when a terminally ill patient receives aggressive CPR. This arises from:', '["Ethical dilemma","Legal obligation","Personal values conflict","Inadequate staffing"]'::jsonb, 2, 'Moral distress occurs when actions conflict with personal ethics.', 'Ethics, Law & Management', '⚖️', true),
(4249, 'End-of-Life Care and Ethical Considerations', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient dies, and the family requests cultural rituals. The nurse should:', '["Limit time with the body","Accommodate requests if possible","Discourage rituals","Speed up postmortem care"]'::jsonb, 1, 'Culturally sensitive care includes honoring death rituals.', 'Ethics, Law & Management', '⚖️', true),
(4250, 'End-of-Life Care and Ethical Considerations', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with advanced dementia develops pneumonia. The family requests antibiotics. The nurse discusses:', '["Curative vs. comfort-focused goals","Cost of treatment","Legal implications","Antibiotic resistance"]'::jsonb, 0, 'Align treatment with goals (e.g., comfort vs. life-prolongation).', 'Ethics, Law & Management', '⚖️', true),
(4251, 'End-of-Life Care and Ethical Considerations', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient’s healthcare proxy requests withdrawal of ventilatory support. The nurse’s role is to:', '["Advocate for continued support","Ensure the decision aligns with patient wishes","Refuse to participate","Delay the decision"]'::jsonb, 1, 'Healthcare proxies speak for patients; nurses ensure decisions reflect patient values.', 'Ethics, Law & Management', '⚖️', true),
(4252, 'End-of-Life Care and Ethical Considerations', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with terminal agitation is prescribed midazolam. The primary goal is:', '["Prolong life","Relieve suffering","Induce sleep","Cure delirium"]'::jsonb, 1, 'Midazolam provides sedation for comfort in terminal agitation.', 'Ethics, Law & Management', '⚖️', true),
(4253, 'End-of-Life Care and Ethical Considerations', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A nurse discusses euthanasia with a patient. In the U.S., euthanasia is:', '["Legal everywhere","Illegal but physician-assisted suicide is permitted in some states","Mandatory for terminal illness","Encouraged in hospice"]'::jsonb, 1, 'Euthanasia is illegal; physician-assisted death (e.g., in Oregon) requires strict criteria.', 'Ethics, Law & Management', '⚖️', true),
(4254, 'End-of-Life Care and Ethical Considerations', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'After a patient’s death, the nurse provides bereavement support by:', '["Avoiding the family","Offering grief counseling resources","Discouraging funeral attendance","Minimizing the loss"]'::jsonb, 1, 'Bereavement support includes counseling referrals and compassionate presence.', 'Ethics, Law & Management', '⚖️', true),
(4255, 'Burns and Fluid Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient has burns to the anterior trunk, entire right arm, and anterior left leg. Using the Rule of Nines, the TBSA burned is:', '["27%","36%","45%","54%"]'::jsonb, 1, 'Anterior trunk (18%) + right arm (9%) + anterior left leg (9%) = 36%. Anterior leg is 9% (each leg is 18%, so anterior half is 9%).', 'Burns & Trauma', '🔥', true),
(4256, 'Burns and Fluid Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A 70 kg patient with 50% TBSA burns requires fluid resuscitation. The Parkland formula calculates the 24-hour fluid as:', '["14,000 mL","7,000 mL","3,500 mL","28,000 mL"]'::jsonb, 0, 'Parkland formula: 4 mL \times kg \times %TBSA = 4 \times 70 \times 50 = 14,000 mL.', 'Burns & Trauma', '🔥', true),
(4257, 'Burns and Fluid Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with facial burns and singed nasal hairs is at risk for:', '["Hypothermia","Airway obstruction","Hyperglycemia","Hypokalemia"]'::jsonb, 1, 'Singed nasal hairs suggest inhalation injury, which can cause airway edema.', 'Burns & Trauma', '🔥', true),
(4258, 'Burns and Fluid Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'During burn resuscitation, urine output should be maintained at:', '["5-10 mL/hr","30-50 mL/hr","60-80 mL/hr","$>$100 mL/hr"]'::jsonb, 1, 'Adequate urine output (30-50 mL/hr in adults) indicates sufficient renal perfusion.', 'Burns & Trauma', '🔥', true),
(4259, 'Burns and Fluid Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with electrical burns is at highest risk for:', '["Renal failure","Cardiac arrhythmias","Liver failure","Pancreatitis"]'::jsonb, 1, 'Electrical current can disrupt cardiac conduction, causing arrhythmias.', 'Burns & Trauma', '🔥', true),
(4260, 'Burns and Fluid Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A burn patient develops hemoglobinuria. The nurse should:', '["Increase fluid rate","Administer mannitol","Give sodium bicarbonate","All of the above"]'::jsonb, 3, 'Hemoglobinuria from muscle breakdown requires aggressive hydration, alkalinization, and diuresis to prevent ATN.', 'Burns & Trauma', '🔥', true),
(4261, 'Burns and Fluid Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with circumferential full-thickness burns to the chest has difficulty breathing. The nurse anticipates:', '["Escharotomy","Fasciotomy","Bronchoscopy","Chest tube insertion"]'::jsonb, 0, 'Circumferential eschar restricts chest expansion; escharotomy relieves pressure.', 'Burns & Trauma', '🔥', true),
(4262, 'Burns and Fluid Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'Silver sulfadiazine is used for burns to:', '["Promote epithelialization","Provide analgesia","Prevent infection","Debride necrotic tissue"]'::jsonb, 2, 'Silver sulfadiazine is a topical antimicrobial.', 'Burns & Trauma', '🔥', true),
(4263, 'Burns and Fluid Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A burn patient has a core temperature of 35°C (95°F). The nurse should:', '["Apply ice packs","Increase room temperature","Use warm IV fluids","B and C"]'::jsonb, 3, 'Burn patients lose heat through damaged skin; external warming and warm fluids prevent hypothermia.', 'Burns & Trauma', '🔥', true),
(4264, 'Burns and Fluid Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'The emergent phase of burns lasts:', '["0-48 hours","3-7 days","1-3 weeks","$>$3 weeks"]'::jsonb, 0, 'The emergent phase (0-48 hours) focuses on fluid resuscitation and airway management.', 'Burns & Trauma', '🔥', true),
(4265, 'Burns and Fluid Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with a chemical burn should be treated with:', '["Neutralizing agents","Copious water irrigation","Dry dressings","Ice application"]'::jsonb, 1, 'Immediate irrigation dilutes and removes chemicals.', 'Burns & Trauma', '🔥', true),
(4266, 'Burns and Fluid Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'Curling’s ulcer prevention in burn patients includes:', '["Proton pump inhibitors","Antacids","Sucralfate","All of the above"]'::jsonb, 3, 'Stress ulcer prophylaxis (e.g., PPIs) is standard for major burns.', 'Burns & Trauma', '🔥', true),
(4267, 'Burns and Fluid Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A burn patient with hyperkalemia likely has:', '["Metabolic alkalosis","Cell lysis","Over-resuscitation","Hypoglycemia"]'::jsonb, 1, 'Burn tissue releases potassium into circulation.', 'Burns & Trauma', '🔥', true),
(4268, 'Burns and Fluid Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'Tetanus prophylaxis is given for burns if:', '["The last booster was $>$5 years ago","The burn is superficial","The patient is immunocompromised","Bleeding is controlled"]'::jsonb, 0, 'Tetanus-prone wounds require booster if $>$5 years since last dose.', 'Burns & Trauma', '🔥', true),
(4269, 'Burns and Fluid Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with 30% TBSA burns has a urine output of 20 mL/hr. The nurse should:', '["Decrease IV fluid rate","Increase IV fluid rate","Administer furosemide","Check serum creatinine"]'::jsonb, 1, 'Low urine output indicates inadequate resuscitation; increase fluids.', 'Burns & Trauma', '🔥', true),
(4270, 'Burns and Fluid Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'Nutritional support for burn patients emphasizes:', '["High-protein, high-calorie diet","Low-carbohydrate diet","Fluid restriction","Vitamin D restriction"]'::jsonb, 0, 'Hypermetabolism requires \uparrow protein/calories for wound healing.', 'Burns & Trauma', '🔥', true),
(4271, 'Burns and Fluid Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A burn patient develops hoarseness and stridor. The nurse should:', '["Administer racemic epinephrine","Prepare for intubation","Encourage coughing","Apply oxygen"]'::jsonb, 1, 'Hoarseness/stridor signal upper airway edema; intubation may be needed.', 'Burns & Trauma', '🔥', true),
(4272, 'Burns and Fluid Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'Autografting is performed during the:', '["Emergent phase","Acute phase","Rehabilitative phase","Resuscitation phase"]'::jsonb, 1, 'Autografts are placed after wound excision in the acute phase (3-7 days post-burn).', 'Burns & Trauma', '🔥', true),
(4273, 'Burns and Fluid Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'Compartment syndrome in a burn patient is suggested by:', '["Increased pulses","Pain with passive movement","Warm extremities","Hypertension"]'::jsonb, 1, 'Pain on passive stretch indicates compartment syndrome.', 'Burns & Trauma', '🔥', true),
(4274, 'Burns and Fluid Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with a major burn receives morphine IV. The nurse prioritizes monitoring for:', '["Respiratory depression","Hypertension","Urinary retention","Constipation"]'::jsonb, 0, 'IV opioids can cause respiratory depression in burn patients.', 'Burns & Trauma', '🔥', true),
(4275, 'Trauma and Emergency Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'During the primary survey of a trauma patient, the nurse assesses:', '["Airway, Breathing, Circulation, Disability, Exposure","History, Allergies, Medications","Vital signs, Pain, Past medical history","Neurological status, Skin integrity"]'::jsonb, 0, 'Primary survey follows ABCDE to identify life threats.', 'Burns & Trauma', '🔥', true),
(4276, 'Trauma and Emergency Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A trauma patient with absent breath sounds and tracheal deviation likely has:', '["Tension pneumothorax","Cardiac tamponade","Hemothorax","Flail chest"]'::jsonb, 0, 'Tracheal deviation and absent breath sounds indicate tension pneumothorax.', 'Burns & Trauma', '🔥', true),
(4277, 'Trauma and Emergency Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with pelvic fracture is at risk for:', '["Fat embolism","Massive hemorrhage","Neurogenic shock","A and B"]'::jsonb, 3, 'Pelvic fractures can cause bleeding (venous plexus injury) and fat embolism.', 'Burns & Trauma', '🔥', true),
(4278, 'Trauma and Emergency Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'The nurse suspects neurogenic shock in a patient with:', '["Tachycardia and hypotension","Bradycardia and hypotension","Hypertension and bradycardia","Tachycardia and hypertension"]'::jsonb, 1, 'Neurogenic shock (from spinal injury) causes bradycardia and hypotension due to loss of sympathetic tone.', 'Burns & Trauma', '🔥', true),
(4279, 'Trauma and Emergency Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A trauma patient has a GCS of 7. This indicates:', '["Mild brain injury","Moderate brain injury","Severe brain injury","No brain injury"]'::jsonb, 2, 'GCS \le8 indicates severe brain injury.', 'Burns & Trauma', '🔥', true),
(4280, 'Trauma and Emergency Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'For a patient with uncontrolled hemorrhage, permissive hypotension is used to:', '["Prevent coagulopathy","Avoid dislodging clots","Reduce blood loss","All of the above"]'::jsonb, 3, 'Permissive hypotension (SBP 80-90 mmHg) prevents exacerbating bleeding until surgical control.', 'Burns & Trauma', '🔥', true),
(4281, 'Trauma and Emergency Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with penetrating abdominal trauma has evisceration. The nurse should:', '["Replace organs","Cover with moist sterile dressing","Apply pressure","Irrigate with saline"]'::jsonb, 1, 'Moist sterile dressings protect exposed viscera.', 'Burns & Trauma', '🔥', true),
(4282, 'Trauma and Emergency Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'The massive transfusion protocol typically includes:', '["1:1:1 ratio of PRBCs:FFP:platelets","PRBCs only","Crystalloids only","4:1 ratio of PRBCs:FFP"]'::jsonb, 0, '1:1:1 ratio mimics whole blood and prevents coagulopathy.', 'Burns & Trauma', '🔥', true),
(4283, 'Trauma and Emergency Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A trauma patient with open tibial fracture should receive:', '["Tetanus toxoid","Broad-spectrum antibiotics","Both A and B","Neither"]'::jsonb, 2, 'Open fractures require tetanus prophylaxis and antibiotics.', 'Burns & Trauma', '🔥', true),
(4284, 'Trauma and Emergency Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with blunt chest trauma has paradoxical chest movement. This suggests:', '["Pneumothorax","Flail chest","Hemothorax","Pulmonary contusion"]'::jsonb, 1, 'Paradoxical movement indicates flail chest (segmental rib fractures).', 'Burns & Trauma', '🔥', true),
(4285, 'Trauma and Emergency Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'For a patient with suspected spinal injury, the nurse:', '["Log-rolls with spine immobilization","Sits the patient up","Flexes the neck","Removes the collar"]'::jsonb, 0, 'Log-rolling maintains spinal alignment.', 'Burns & Trauma', '🔥', true),
(4286, 'Trauma and Emergency Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A trauma patient has Battle’s sign and raccoon eyes. The nurse suspects:', '["Basilar skull fracture","Orbital fracture","Nasal fracture","Cervical spine injury"]'::jsonb, 0, 'Battle’s sign (mastoid ecchymosis) and raccoon eyes suggest basilar skull fracture.', 'Burns & Trauma', '🔥', true),
(4287, 'Trauma and Emergency Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with cardiac tamponade may have:', '["Muffled heart sounds","Hypertension","Bounding pulses","Increased urine output"]'::jsonb, 0, 'Beck’s triad: muffled heart sounds, JVD, hypotension.', 'Burns & Trauma', '🔥', true),
(4288, 'Trauma and Emergency Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'The secondary survey includes:', '["AMPLE history","Head-to-toe assessment","Vital signs","All of the above"]'::jsonb, 3, 'Secondary survey is a thorough assessment after ABCDE stabilization.', 'Burns & Trauma', '🔥', true),
(4289, 'Trauma and Emergency Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A trauma patient with a sucking chest wound should be treated with:', '["Occlusive dressing taped on three sides","Fully taped occlusive dressing","No dressing","Packing the wound"]'::jsonb, 0, 'Taping on three sides allows air escape during exhalation, preventing tension pneumothorax.', 'Burns & Trauma', '🔥', true),
(4290, 'Trauma and Emergency Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with a femur fracture is at risk for fat embolism syndrome. Signs include:', '["Hypoxia and petechiae","Hypertension and bradycardia","Hyperglycemia","Polyuria"]'::jsonb, 0, 'Fat embolism causes respiratory distress (hypoxia) and petechiae.', 'Burns & Trauma', '🔥', true),
(4291, 'Trauma and Emergency Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A trauma patient has a Glasgow Coma Scale of 10. The nurse should:', '["Prepare for intubation","Administer mannitol","Elevate the head of bed","All of the above"]'::jsonb, 3, 'GCS \le10 requires airway protection (intubation) and measures to reduce ICP (HOB elevation, mannitol).', 'Burns & Trauma', '🔥', true),
(4292, 'Trauma and Emergency Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'For hemorrhagic shock, the initial fluid of choice is:', '["Lactated Ringer’s","5% albumin","Hypertonic saline","Packed RBCs"]'::jsonb, 0, 'Crystalloids (e.g., LR) are first-line for volume resuscitation.', 'Burns & Trauma', '🔥', true),
(4293, 'Trauma and Emergency Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A trauma patient with suspected internal bleeding should receive:', '["Tranexamic acid (TXA)","Heparin","Warfarin","Aspirin"]'::jsonb, 0, 'TXA reduces mortality in trauma-associated hemorrhage.', 'Burns & Trauma', '🔥', true),
(4294, 'Trauma and Emergency Resuscitation', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'During rapid sequence intubation, the nurse prepares:', '["Sedative and paralytic","Anticholinergic","Vasopressor","Bronchodilator"]'::jsonb, 0, 'RSI uses a sedative (e.g., etomidate) and paralytic (e.g., succinylcholine).', 'Burns & Trauma', '🔥', true),
(4295, 'Postoperative Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient s/p abdominal surgery has a BP of 85/50 mmHg and HR 120 bpm. The nurse suspects:', '["Hemorrhage","Pain","Infection","Atelectasis"]'::jsonb, 0, 'Tachycardia and hypotension indicate hypovolemia (e.g., bleeding).', 'Anaesthesia & Perioperative Care', '💉', true),
(4296, 'Postoperative Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient s/p thyroidectomy has stridor and agitation. The nurse should:', '["Administer morphine","Prepare for reintubation","Encourage coughing","Apply oxygen"]'::jsonb, 1, 'Stridor suggests laryngeal edema or hematoma, risking airway obstruction.', 'Anaesthesia & Perioperative Care', '💉', true),
(4297, 'Postoperative Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'To prevent DVT in postoperative patients, the nurse ensures:', '["Early ambulation","SCDs","Anticoagulants","All of the above"]'::jsonb, 3, 'Multimodal prophylaxis reduces DVT risk.', 'Anaesthesia & Perioperative Care', '💉', true),
(4298, 'Postoperative Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient s/p bowel resection has absent bowel sounds and distension. The nurse suspects:', '["Paralytic ileus","Bowel obstruction","Peritonitis","Anastomotic leak"]'::jsonb, 0, 'Ileus is common post-op; bowel sounds are absent/hypoactive.', 'Anaesthesia & Perioperative Care', '💉', true),
(4299, 'Postoperative Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with PCA morphine has a respiratory rate of 8/min. The nurse should:', '["Administer naloxone","Discontinue PCA","Stimulate the patient","Increase oxygen flow"]'::jsonb, 0, 'Naloxone reverses opioid-induced respiratory depression.', 'Anaesthesia & Perioperative Care', '💉', true),
(4300, 'Postoperative Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient s/p CABG has mediastinal tube drainage of 200 mL/hr. The nurse should:', '["Clamp the tube","Notify the surgeon","Increase suction","Administer protamine"]'::jsonb, 1, '$>$100-200 mL/hr drainage may indicate bleeding; urgent intervention is needed.', 'Anaesthesia & Perioperative Care', '💉', true),
(4301, 'Postoperative Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient s/p hip replacement has acute confusion. The nurse FIRST assesses for:', '["Hypoxia","Stroke","Pain","Urinary retention"]'::jsonb, 0, 'Hypoxia is a reversible cause of delirium.', 'Anaesthesia & Perioperative Care', '💉', true),
(4302, 'Postoperative Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient s/p laminectomy has new lower extremity weakness. The nurse suspects:', '["Normal recovery","Hematoma compressing the cord","DVT","Infection"]'::jsonb, 1, 'New weakness suggests spinal cord compression (e.g., epidural hematoma).', 'Anaesthesia & Perioperative Care', '💉', true),
(4303, 'Postoperative Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'To prevent atelectasis postoperatively, the nurse encourages:', '["Incentive spirometry","Bed rest","Fluid restriction","Supine position"]'::jsonb, 0, 'Incentive spirometry promotes lung expansion.', 'Anaesthesia & Perioperative Care', '💉', true),
(4304, 'Postoperative Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient s/p TURP has pink-tinged urine and bladder spasms. This is:', '["Normal","Indicative of infection","Sign of hemorrhage","Urinary retention"]'::jsonb, 0, 'Hematuria and spasms are common after TURP.', 'Anaesthesia & Perioperative Care', '💉', true),
(4305, 'Postoperative Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with an NG tube to suction has metabolic alkalosis. The nurse anticipates:', '["Hypokalemia","Hypercalcemia","Hypermagnesemia","Hypernatremia"]'::jsonb, 0, 'Gastric suctioning causes loss of H⁺, K⁺, and Cl⁻, leading to hypokalemic metabolic alkalosis.', 'Anaesthesia & Perioperative Care', '💉', true),
(4306, 'Postoperative Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient s/p abdominal surgery has fever and purulent wound drainage on day 7. The nurse suspects:', '["Atelectasis","Wound infection","Pneumonia","UTI"]'::jsonb, 1, 'Wound infections typically present on days 5-7.', 'Anaesthesia & Perioperative Care', '💉', true),
(4307, 'Postoperative Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with epidural analgesia has a sensory level at T4. The nurse monitors for:', '["Respiratory depression","Hypertension","Bradycardia","Urinary retention"]'::jsonb, 0, 'High thoracic blocks can cause respiratory muscle weakness.', 'Anaesthesia & Perioperative Care', '💉', true),
(4308, 'Postoperative Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient s/p craniotomy has decreased LOC and unilateral pupil dilation. The nurse should:', '["Administer mannitol","Prepare for CT scan","Hyperventilate the patient","All of the above"]'::jsonb, 3, 'Signs suggest herniation; interventions reduce ICP.', 'Anaesthesia & Perioperative Care', '💉', true),
(4309, 'Postoperative Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with an ileostomy has high-output losses. The nurse is concerned about:', '["Hypokalemia","Hypercalcemia","Hypoglycemia","Hypermagnesemia"]'::jsonb, 0, 'Ileostomy losses cause dehydration and hypokalemia.', 'Anaesthesia & Perioperative Care', '💉', true),
(4310, 'Postoperative Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient s/p pneumonectomy has sudden SOB and hypotension. The nurse suspects:', '["Pneumonia","Pulmonary embolism","Tension pneumothorax","Myocardial infarction"]'::jsonb, 1, 'Immobility and surgery increase PE risk.', 'Anaesthesia & Perioperative Care', '💉', true),
(4311, 'Postoperative Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'To prevent aspiration in a patient with reduced gag reflex, the nurse:', '["Elevates the head of bed 30-45 degrees","Encourages oral intake","Administers sedatives","Places in supine position"]'::jsonb, 0, 'HOB elevation reduces aspiration risk.', 'Anaesthesia & Perioperative Care', '💉', true),
(4312, 'Postoperative Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with a chest tube has continuous bubbling in the water seal chamber. The nurse should:', '["Clamp the tube","Check for an air leak","Increase suction","Notify the provider"]'::jsonb, 1, 'Continuous bubbling indicates an air leak (e.g., from system disconnection).', 'Anaesthesia & Perioperative Care', '💉', true),
(4313, 'Postoperative Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient s/p carotid endarterectomy has hoarseness. The nurse assesses for:', '["Recurrent laryngeal nerve injury","Hypocalcemia","Stroke","Hematoma"]'::jsonb, 0, 'Hoarseness suggests vocal cord paralysis from nerve injury.', 'Anaesthesia & Perioperative Care', '💉', true),
(4314, 'Postoperative Critical Care', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'Early mobilization postoperatively prevents:', '["Pneumonia","Pressure ulcers","Muscle atrophy","All of the above"]'::jsonb, 3, 'Early ambulation reduces complications of immobility.', 'Anaesthesia & Perioperative Care', '💉', true),
(4315, 'Nutrition in the Critically Ill', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with a functioning GI tract is started on parenteral nutrition. The nurse knows this is indicated only if:', '["Enteral nutrition is contraindicated","The patient prefers it","Blood glucose is elevated","Albumin is low"]'::jsonb, 0, 'PN is for patients who cannot tolerate enteral nutrition (e.g., bowel obstruction, ileus).', 'GI, Endocrine & Metabolic', '🍽️', true),
(4316, 'Nutrition in the Critically Ill', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with refeeding syndrome is at risk for:', '["Hypophosphatemia","Hyperkalemia","Hypercalcemia","Hypermagnesemia"]'::jsonb, 0, 'Refeeding syndrome causes hypophosphatemia, hypokalemia, and hypomagnesemia.', 'GI, Endocrine & Metabolic', '🍽️', true),
(4317, 'Nutrition in the Critically Ill', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'To prevent aspiration during enteral feeding, the nurse:', '["Keeps HOB elevated 30-45 degrees","Checks gastric residuals","Avoids bolus feeds","All of the above"]'::jsonb, 3, 'These measures reduce aspiration risk.', 'GI, Endocrine & Metabolic', '🍽️', true),
(4318, 'Nutrition in the Critically Ill', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with severe pancreatitis should receive:', '["TPN immediately","Enteral nutrition via NJ tube","Oral diet","IV dextrose only"]'::jsonb, 1, 'Enteral nutrition (distal to ligament of Treitz) maintains gut integrity and is preferred over TPN.', 'GI, Endocrine & Metabolic', '🍽️', true),
(4319, 'Nutrition in the Critically Ill', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'The BEST marker for nutritional status in critical illness is:', '["Albumin","Prealbumin","Transferrin","Nitrogen balance"]'::jsonb, 1, 'Prealbumin has a short half-life (2-3 days) and reflects recent protein status.', 'GI, Endocrine & Metabolic', '🍽️', true),
(4320, 'Nutrition in the Critically Ill', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient on TPN has hyperglycemia. The nurse should:', '["Add insulin to TPN","Decrease dextrose concentration","Administer subcutaneous insulin","A or C"]'::jsonb, 3, 'Hyperglycemia is managed with insulin (added to TPN or given subcutaneously).', 'GI, Endocrine & Metabolic', '🍽️', true),
(4321, 'Nutrition in the Critically Ill', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with burns requires increased:', '["Protein and calories","Aat-soluble vitamins","Carbohydrates only","Iron"]'::jsonb, 0, 'Hypermetabolism increases protein/calorie needs.', 'GI, Endocrine & Metabolic', '🍽️', true),
(4322, 'Nutrition in the Critically Ill', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with gastric residuals of 300 mL during enteral feeding should:', '["Stop feeding and notify provider","Increase feeding rate","Flush the tube","Administer metoclopramide"]'::jsonb, 0, 'High residuals ($>$250-500 mL) indicate intolerance; hold feeding to prevent aspiration.', 'GI, Endocrine & Metabolic', '🍽️', true),
(4323, 'Nutrition in the Critically Ill', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'Glutamine supplementation in critical illness may:', '["Reduce infections","Increase blood glucose","Cause diarrhea","Elevate liver enzymes"]'::jsonb, 0, 'Glutamine supports gut immunity and may reduce infections.', 'GI, Endocrine & Metabolic', '🍽️', true),
(4324, 'Nutrition in the Critically Ill', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with short bowel syndrome is at risk for:', '["Vitamin B12 deficiency","Hypercalcemia","Hypoglycemia","Hyperphosphatemia"]'::jsonb, 0, 'Terminal ileum resection impairs B12 absorption.', 'GI, Endocrine & Metabolic', '🍽️', true),
(4325, 'Nutrition in the Critically Ill', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'The nurse calculates protein needs for a critically ill patient as:', '["0.8 g/kg/day","1.2-2.0 g/kg/day","2.5-3.0 g/kg/day","4.0 g/kg/day"]'::jsonb, 1, 'Critically ill patients need \uparrow protein for healing.', 'GI, Endocrine & Metabolic', '🍽️', true),
(4326, 'Nutrition in the Critically Ill', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with diarrhea on enteral feeds should be assessed for:', '["Osmotic load","Infection (C. diff)","Medication side effects","All of the above"]'::jsonb, 3, 'Diarrhea has multiple causes; evaluate all.', 'GI, Endocrine & Metabolic', '🍽️', true),
(4327, 'Nutrition in the Critically Ill', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'Cycling TPN over 12 hours helps:', '["Prevent hyperglycemia","Restore endogenous insulin production","Reduce infection risk","Improve liver function"]'::jsonb, 1, 'Cycling allows insulin levels to normalize, easing transition to oral intake.', 'GI, Endocrine & Metabolic', '🍽️', true),
(4328, 'Nutrition in the Critically Ill', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with hepatic encephalopathy should restrict:', '["Protein","Carbohydrates","Fat","Vitamins"]'::jsonb, 0, 'Protein restriction reduces ammonia production.', 'GI, Endocrine & Metabolic', '🍽️', true),
(4329, 'Nutrition in the Critically Ill', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'Selenium and zinc are added to nutrition support to:', '["Enhance wound healing","Reduce oxidative stress","Support immune function","All of the above"]'::jsonb, 3, 'Trace elements aid healing, immunity, and antioxidant defenses.', 'GI, Endocrine & Metabolic', '🍽️', true),
(4330, 'Nutrition in the Critically Ill', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with ARDS on enteral nutrition should receive:', '["High-fat formula","Omega-3 fatty acids","Immune-modulating formula","B and C"]'::jsonb, 3, 'Omega-3 and immune-modulating formulas may reduce inflammation in ARDS.', 'GI, Endocrine & Metabolic', '🍽️', true),
(4331, 'Nutrition in the Critically Ill', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with refeeding syndrome has cardiac arrhythmias. The nurse corrects:', '["Hypophosphatemia","Hypokalemia","Hypomagnesemia","All of the above"]'::jsonb, 3, 'Electrolyte imbalances contribute to arrhythmias.', 'GI, Endocrine & Metabolic', '🍽️', true),
(4332, 'Nutrition in the Critically Ill', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with a feeding tube receives phenytoin. The nurse should:', '["Hold feeds 2 hours before/after dose","Crush the tablet","Administer with feeds","Give IV"]'::jsonb, 0, 'Enteral feeds reduce phenytoin absorption; hold feeds around doses.', 'GI, Endocrine & Metabolic', '🍽️', true),
(4333, 'Nutrition in the Critically Ill', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'The nurse monitors for essential fatty acid deficiency in long-term TPN by assessing:', '["Dry, scaly skin","Hyperglycemia","Jaundice","Edema"]'::jsonb, 0, 'Fatty acid deficiency causes dermatitis and hair loss.', 'GI, Endocrine & Metabolic', '🍽️', true),
(4334, 'Nutrition in the Critically Ill', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with high-output enterocutaneous fistula should receive:', '["TPN","Elemental enteral formula","Oral rehydration solution","A or B"]'::jsonb, 3, 'TPN or elemental formulas (easily absorbed) are used to manage losses.', 'GI, Endocrine & Metabolic', '🍽️', true),
(4335, 'Disaster Preparedness and Triage', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'During a mass casualty event, the START triage system categorizes a patient with respirations $>$30/min as:', '["Red (Immediate)","Yellow (Delayed)","Green (Minor)","Black (Deceased/Expectant)"]'::jsonb, 0, 'Respirations $>$30/min indicate respiratory distress (red tag).', 'Disaster & Emergency Nursing', '🚨', true),
(4336, 'Disaster Preparedness and Triage', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'The ICU nurse’s role in disaster management includes:', '["Triage in the ED","Care of critically ill patients","Community evacuation","Public communication"]'::jsonb, 1, 'ICU nurses maintain care of unstable patients.', 'Disaster & Emergency Nursing', '🚨', true),
(4337, 'Disaster Preparedness and Triage', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with agonal respirations is triaged as:', '["Red","Yellow","Green","Black"]'::jsonb, 3, 'Agonal breaths are ineffective; black tag indicates expectant.', 'Disaster & Emergency Nursing', '🚨', true),
(4338, 'Disaster Preparedness and Triage', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'In a radiation disaster, potassium iodide protects the:', '["Thyroid gland","Bone marrow","GI tract","Lungs"]'::jsonb, 0, 'KI blocks radioactive iodine uptake by the thyroid.', 'Disaster & Emergency Nursing', '🚨', true),
(4339, 'Disaster Preparedness and Triage', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'The principle of "greatest good for the greatest number" is:', '["Utilitarianism","Autonomy","Justice","Beneficence"]'::jsonb, 0, 'Utilitarianism prioritizes population-level benefits.', 'Disaster & Emergency Nursing', '🚨', true),
(4340, 'Disaster Preparedness and Triage', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'For a patient with uncontrolled hemorrhage, the nurse applies:', '["Direct pressure","Tourniquet","Hemostatic agent","All of the above"]'::jsonb, 3, 'All are hemorrhage control strategies.', 'Disaster & Emergency Nursing', '🚨', true),
(4341, 'Disaster Preparedness and Triage', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with smallpox requires:', '["Airborne precautions","Contact precautions","Droplet precautions","Standard precautions"]'::jsonb, 0, 'Smallpox is airborne-spread.', 'Disaster & Emergency Nursing', '🚨', true),
(4342, 'Disaster Preparedness and Triage', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'In a chemical attack with sarin gas, the nurse administers:', '["Atropine and pralidoxime","Naloxone","Cyanide antidote kit","Flumazenil"]'::jsonb, 0, 'Atropine and pralidoxime are antidotes for nerve agents.', 'Disaster & Emergency Nursing', '🚨', true),
