(4345, 'Disaster Preparedness and Triage', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with an open fracture is triaged as yellow. This means:', '["Immediate care needed","Care can be delayed","Minor injury","Expectant"]'::jsonb, 1, 'Yellow (delayed) for serious but not immediately life-threatening injuries.', 'Disaster & Emergency Nursing', '🚨', true),
(4346, 'Disaster Preparedness and Triage', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'In a disaster, decontamination should occur:', '["Before entering the ED","After triage","During treatment","At discharge"]'::jsonb, 0, 'Decontamination prevents secondary exposure.', 'Disaster & Emergency Nursing', '🚨', true),
(4347, 'Disaster Preparedness and Triage', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with severe burns and multisystem trauma in a resource-limited disaster is triaged as black because:', '["Survival is unlikely","The patient is deceased","Resources are needed elsewhere","A and C"]'::jsonb, 3, 'Black tag is for patients with low survival probability to conserve resources.', 'Disaster & Emergency Nursing', '🚨', true),
(4348, 'Disaster Preparedness and Triage', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'The nurse’s ethical obligation during a disaster includes:', '["Providing care within scope","Abandoning the facility","Refusing hazardous assignments","Prioritizing personal safety"]'::jsonb, 0, 'Nurses must provide care but can expect reasonable safety measures.', 'Disaster & Emergency Nursing', '🚨', true),
