(4350, 'Disaster Preparedness and Triage', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A walking wounded patient with a minor laceration is triaged as:', '["Red","Yellow","Green","Black"]'::jsonb, 2, 'Green (minor) for ambulatory patients with minor injuries.', 'Disaster & Emergency Nursing', '🚨', true),
(4351, 'Disaster Preparedness and Triage', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'In a biological attack with anthrax, the nurse uses:', '["Standard precautions","Airborne precautions","Contact precautions","Droplet precautions"]'::jsonb, 0, 'Anthrax is not transmitted person-to-person.', 'Disaster & Emergency Nursing', '🚨', true),
(4352, 'Disaster Preparedness and Triage', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'The nurse’s role in shelter-in-place during radiation exposure is to:', '["Close windows and doors","Evacuate immediately","Distribute KI","Set up decontamination"]'::jsonb, 0, 'Shelter-in-place reduces exposure.', 'Disaster & Emergency Nursing', '🚨', true),
(4353, 'Disaster Preparedness and Triage', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'Psychological first aid includes:', '["Active listening","Forcing discussion of trauma","Avoiding eye contact","Providing false reassurance"]'::jsonb, 0, 'Active listening supports coping.', 'Disaster & Emergency Nursing', '🚨', true),
(4354, 'Disaster Preparedness and Triage', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A disaster drill evaluates:', '["Communication systems","Resource allocation","Staff response","All of the above"]'::jsonb, 3, 'Drills test all aspects of disaster response.', 'Disaster & Emergency Nursing', '🚨', true),
(4355, 'Blood Transfusion Reactions and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient develops urticaria and itching during a blood transfusion. The nurse should:', '["Stop the transfusion","Administer diphenhydramine","Slow the infusion rate","A and B"]'::jsonb, 3, 'Urticaria suggests mild allergic reaction; stop transfusion and give antihistamine.', 'Laboratory Sciences & Haematology', '🔬', true),
(4356, 'Blood Transfusion Reactions and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient has fever, chills, and hypotension during transfusion. The nurse suspects:', '["Febrile non-hemolytic reaction","Acute hemolytic reaction","TRALI","TACO"]'::jsonb, 2, 'TRALI presents with acute respiratory distress, fever, and hypotension.', 'Laboratory Sciences & Haematology', '🔬', true),
(4357, 'Blood Transfusion Reactions and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'For suspected acute hemolytic reaction, the nurse’s FIRST action is:', '["Stop the transfusion","Notify the provider","Administer epinephrine","Send blood samples to lab"]'::jsonb, 0, 'Stop transfusion immediately to prevent further hemolysis.', 'Laboratory Sciences & Haematology', '🔬', true),
