(4359, 'Blood Transfusion Reactions and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'To prevent TRALI, blood banks:', '["Use leukocyte-reduced blood","Avoid plasma from multiparous donors","Irradiate blood products","Wash RBCs"]'::jsonb, 1, 'TRALI is often caused by donor antibodies; deferral of multiparous women reduces risk.', 'Laboratory Sciences & Haematology', '🔬', true),
(4360, 'Blood Transfusion Reactions and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient develops cyanosis without respiratory distress during transfusion. The nurse suspects:', '["Methemoglobinemia","Anaphylaxis","Hemolysis","Sepsis"]'::jsonb, 0, 'Methemoglobinemia causes cyanosis unresponsive to oxygen.', 'Laboratory Sciences & Haematology', '🔬', true),
(4361, 'Blood Transfusion Reactions and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'Platelets are administered through:', '["A standard blood filter","A microaggregate filter","No filter","A specialized platelet filter"]'::jsonb, 0, 'Platelets use standard filters; microaggregate filters remove platelets.', 'Laboratory Sciences & Haematology', '🔬', true),
(4362, 'Blood Transfusion Reactions and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with IgA deficiency is at risk for:', '["Anaphylactic reaction","Febrile reaction","TRALI","TACO"]'::jsonb, 0, 'IgA-deficient patients may develop anti-IgA antibodies, causing anaphylaxis.', 'Laboratory Sciences & Haematology', '🔬', true),
(4363, 'Blood Transfusion Reactions and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'For a patient with multiple febrile reactions, the nurse requests:', '["Leukocyte-reduced blood","Washed RBCs","Irradiated blood","Volume-reduced platelets"]'::jsonb, 0, 'Leukocyte reduction prevents febrile non-hemolytic reactions.', 'Laboratory Sciences & Haematology', '🔬', true),
(4364, 'Blood Transfusion Reactions and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with sickle cell disease requires:', '["Leukocyte-reduced, phenotypically matched blood","Standard PRBCs","Platelets","FFP"]'::jsonb, 0, 'Phenotypic matching prevents alloimmunization.', 'Laboratory Sciences & Haematology', '🔬', true),
(4365, 'Blood Transfusion Reactions and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'After a transfusion reaction, the nurse sends:', '["Blood bag, tubing, and post-reaction samples to lab","Pre-transfusion samples only","Urine sample","Stool sample"]'::jsonb, 0, 'All components are needed for investigation.', 'Laboratory Sciences & Haematology', '🔬', true),
(4366, 'Blood Transfusion Reactions and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with iron overload from transfusions receives:', '["Deferoxamine","Vitamin K","Protamine","FFP"]'::jsonb, 0, 'Deferoxamine chelates excess iron.', 'Laboratory Sciences & Haematology', '🔬', true),
(4367, 'Blood Transfusion Reactions and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'To prevent graft-versus-host disease, blood is:', '["Leukocyte-reduced","Washed","Irradiated","Frozen"]'::jsonb, 2, 'Irradiation inactivates donor lymphocytes.', 'Laboratory Sciences & Haematology', '🔬', true),
(4368, 'Blood Transfusion Reactions and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with thrombocytopenia has oozing from IV sites. The nurse prepares to administer:', '["Platelets","Cryoprecipitate","FFP","PRBCs"]'::jsonb, 0, 'Platelets treat thrombocytopenic bleeding.', 'Laboratory Sciences & Haematology', '🔬', true),
(4369, 'Blood Transfusion Reactions and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'During massive transfusion, the nurse monitors for:', '["Hypocalcemia","Hypothermia","Coagulopathy","All of the above"]'::jsonb, 3, 'Citrate toxicity (hypocalcemia), hypothermia, and dilutional coagulopathy are risks.', 'Laboratory Sciences & Haematology', '🔬', true),
(4370, 'Blood Transfusion Reactions and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with hemophilia A needs:', '["Factor VIII concentrate","Factor IX concentrate","FFP","Platelets"]'::jsonb, 0, 'Hemophilia A is factor VIII deficiency.', 'Laboratory Sciences & Haematology', '🔬', true),
(4371, 'Blood Transfusion Reactions and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'FFP is thawed and must be infused within:', '["24 hours","6 hours","4 hours","30 minutes"]'::jsonb, 0, 'Thawed FFP is stable for 24 hours at 1-6°C.', 'Laboratory Sciences & Haematology', '🔬', true),
(4372, 'Blood Transfusion Reactions and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'Cryoprecipitate contains:', '["Fibrinogen and factor VIII","Platelets","Albumin","Immunoglobulins"]'::jsonb, 0, 'Cryoprecipitate is rich in fibrinogen, factor VIII, vWF, and XIII.', 'Laboratory Sciences & Haematology', '🔬', true),
(4373, 'Blood Transfusion Reactions and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with DIC has low fibrinogen. The nurse prepares:', '["Cryoprecipitate","Platelets","PRBCs","FFP"]'::jsonb, 0, 'Cryoprecipitate replaces fibrinogen.', 'Laboratory Sciences & Haematology', '🔬', true),
(4374, 'Blood Transfusion Reactions and Management', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'Autologous transfusion is used for:', '["Elective surgery","Emergency trauma","Neonates","All patients"]'::jsonb, 0, 'Autologous donation is planned for elective procedures.', 'Laboratory Sciences & Haematology', '🔬', true),
(4375, 'Delirium and ICU Psychosis', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient in the ICU is agitated, disoriented, and pulling at IV lines. The nurse FIRST:', '["Administers haloperidol","Applies restraints","Assesses for pain or urinary retention","Increases sedation"]'::jsonb, 2, 'Treat reversible causes (e.g., pain, infection, retention) before pharmacologic interventions.', 'Neurology', '🧠', true),
(4376, 'Delirium and ICU Psychosis', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'The CAM-ICU assesses for delirium using:', '["Acute change, inattention, disorganized thinking, altered LOC","Memory testing only","Physical restraints","Vital signs"]'::jsonb, 0, 'CAM-ICU evaluates acute change, inattention, and either disorganized thinking or altered consciousness.', 'Neurology', '🧠', true),
(4377, 'Delirium and ICU Psychosis', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with hypoactive delirium is at risk for:', '["Falls","Malnutrition","Pressure ulcers","All of the above"]'::jsonb, 3, 'Hypoactive delirium causes immobility and inattention, increasing complications.', 'Neurology', '🧠', true),
(4378, 'Delirium and ICU Psychosis', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'Non-pharmacologic delirium prevention includes:', '["Frequent reorientation","Sleep hygiene","Early mobilization","All of the above"]'::jsonb, 3, 'Multicomponent interventions reduce delirium incidence.', 'Neurology', '🧠', true),
(4379, 'Delirium and ICU Psychosis', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with alcohol withdrawal delirium should receive:', '["Benzodiazepines","Antipsychotics","Opioids","Barbiturates"]'::jsonb, 0, 'Benzodiazepines are first-line for alcohol withdrawal.', 'Neurology', '🧠', true),
(4380, 'Delirium and ICU Psychosis', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'Which drug increases delirium risk?', '["Lorazepam","Acetaminophen","Insulin","Heparin"]'::jsonb, 0, 'Benzodiazepines and anticholinergics are high-risk medications.', 'Neurology', '🧠', true),
(4381, 'Delirium and ICU Psychosis', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with ICU delirium has sundowning. The nurse should:', '["Keep lights on at night","Provide a quiet, dark environment","Restrain the patient","Administer PRN haloperidol"]'::jsonb, 1, 'Darkness promotes melatonin release and sleep.', 'Neurology', '🧠', true),
(4382, 'Delirium and ICU Psychosis', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'The primary goal of delirium management is:', '["Complete resolution of symptoms","Patient safety and symptom control","Discharge planning","Family education"]'::jsonb, 1, 'Safety and comfort are priorities; delirium may persist.', 'Neurology', '🧠', true),
(4383, 'Delirium and ICU Psychosis', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with hyperactive delirium is prescribed quetiapine. The nurse monitors for:', '["QT prolongation","Hypertension","Hyperglycemia","A and C"]'::jsonb, 3, 'Atypical antipsychotics can prolong QT and cause metabolic side effects.', 'Neurology', '🧠', true),
(4384, 'Delirium and ICU Psychosis', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'To reduce delirium, mechanical ventilation protocols include:', '["Daily sedation vacation","Continuous deep sedation","Restraints","Isolation"]'::jsonb, 0, 'Daily awakening trials reduce delirium duration.', 'Neurology', '🧠', true),
(4385, 'Delirium and ICU Psychosis', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with delirium has hallucinations. The nurse should:', '["Reorient and reassure","Argue with the patient","Ignore the behavior","Restrain immediately"]'::jsonb, 0, 'Reorientation and validation reduce distress.', 'Neurology', '🧠', true),
(4386, 'Delirium and ICU Psychosis', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'The ICDSC is used to:', '["Screen for delirium","Diagnose dementia","Assess pain","Monitor sedation"]'::jsonb, 0, 'Intensive Care Delirium Screening Checklist is a validated tool.', 'Neurology', '🧠', true),
(4387, 'Delirium and ICU Psychosis', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'Risk factors for delirium include:', '["Older age","Dementia","Severe illness","All of the above"]'::jsonb, 3, 'Multiple factors increase susceptibility.', 'Neurology', '🧠', true),
(4388, 'Delirium and ICU Psychosis', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with Parkinson’s disease and delirium should avoid:', '["Haloperidol","Quetiapine","Melatonin","Dexmedetomidine"]'::jsonb, 0, 'Haloperidol worsens Parkinsonism; quetiapine is safer.', 'Neurology', '🧠', true),
(4389, 'Delirium and ICU Psychosis', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'Delirium differs from dementia in that delirium:', '["Has acute onset","Is irreversible","Has a chronic course","Affects memory only"]'::jsonb, 0, 'Delirium is acute and fluctuating; dementia is chronic and progressive.', 'Neurology', '🧠', true),
(4390, 'Delirium and ICU Psychosis', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A patient with hypoactive delirium is prescribed rivastigmine. This is:', '["Not recommended","First-line treatment","Used for Alzheimer’s","A standard intervention"]'::jsonb, 0, 'Rivastigmine is for dementia, not delirium, and may worsen outcomes.', 'Neurology', '🧠', true),
(4391, 'Delirium and ICU Psychosis', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'Melatonin is used in ICU delirium to:', '["Promote sleep-wake cycle","Reduce agitation","Treat psychosis","Improve memory"]'::jsonb, 0, 'Melatonin regulates circadian rhythms.', 'Neurology', '🧠', true),
(4392, 'Delirium and ICU Psychosis', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'A delirious patient attempts to climb out of bed. The nurse should:', '["Use restraints","Assign a sitter","Administer benzodiazepines","Lock the door"]'::jsonb, 1, 'Sitters are safer than restraints for fall prevention.', 'Neurology', '🧠', true),
(4393, 'Delirium and ICU Psychosis', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'Post-ICU delirium may lead to:', '["Long-term cognitive impairment","PTSD","Functional decline","All of the above"]'::jsonb, 3, 'Delirium is associated with poor long-term outcomes.', 'Neurology', '🧠', true),
(4394, 'Delirium and ICU Psychosis', 'Easy Approach Council Preparatory Class — ICU Study MCQs', 'Family involvement in delirium management includes:', '["Providing familiar objects","Assisting with reorientation","Reducing noise","All of the above"]'::jsonb, 3, 'Family presence decreases delirium severity.', 'Neurology', '🧠', true),
(4395, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'In which one of the following situations atropine is best indicated?', '["Tachycardia","Bradycardia","Hypertension","Hypotension"]'::jsonb, 1, 'Atropine, an anticholinergic, blocks vagal effects on the heart and is the first-line drug for symptomatic bradycardia.', 'Anaesthesia & Perioperative Care', '💉', true),
(4396, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'The most suitable in anaesthesia for geriatric patient is', '["Always give doses at low level","The drugs is not calculated by mg /body weight","General anaesthesia is better than regional in lower part of the body","Local is not indicated"]'::jsonb, 0, 'Elderly patients have reduced organ reserve and drug clearance, so anaesthetic doses are generally reduced and titrated carefully.', 'Anaesthesia & Perioperative Care', '💉', true),
(4397, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'The dose of suxthamethonium for intubation is', '["2mg/kg","0.2mg/kg","100mg for adult","1gm for pediatrics"]'::jsonb, 0, 'Succinylcholine''s typical intubating dose is commonly cited as up to 1-2mg/kg IV for rapid, reliable paralysis during induction.', 'Anaesthesia & Perioperative Care', '💉', true),
(4398, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Laryngoscope is best used for one of the following', '["Visualization of esophagus","Insertion of Nasogastric tube","Intubation","Ventilation"]'::jsonb, 2, 'The laryngoscope is used to lift the tongue/epiglottis and expose the vocal cords for endotracheal tube placement.', 'Anaesthesia & Perioperative Care', '💉', true),
(4399, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'The following drugs are all can be used for regional anaesthesia except one', '["Lidocaine","Bupivacaine","Cocaine","Neostigmine"]'::jsonb, 3, 'Neostigmine is a cholinesterase inhibitor used for neuromuscular blockade reversal, not as a regional anaesthetic agent.', 'Anaesthesia & Perioperative Care', '💉', true),
(4400, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Which One of the following is contraindication of general anaesthesia?', '["Hypotension","Brady cardia","Active chest problems","Hypothermia"]'::jsonb, 2, 'Active, uncontrolled chest/cardiopulmonary disease significantly raises perioperative risk and is a contraindication to elective general anaesthesia until optimised.', 'Anaesthesia & Perioperative Care', '💉', true),
(4401, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Regional anaesthesia is contraindicated in', '["Abrutio placenta","Diagnosis of placenta previa","Thrombocytopenia and elevated bleeding time","Eclampsia"]'::jsonb, 3, 'Eclampsia with coagulopathy or haemodynamic instability is a contraindication to neuraxial techniques; regional anaesthesia is otherwise often preferred in obstetrics.', 'Anaesthesia & Perioperative Care', '💉', true),
(4402, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'To prevent aspiration pneumonia all the following is true except :', '["Rapid intubation","Rapid induction","last time the patient has eaten is before 2 hours","Cricoids pressure"]'::jsonb, 2, 'Aspiration prophylaxis protocols require an adequate NPO period (commonly cited as longer than 2 hours for clear fluids in most guidance); eating shortly before is a risk factor, not a preventive measure.', 'Anaesthesia & Perioperative Care', '💉', true),
(4403, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'All of the following are suitable for aspiration prophylaxis prior to caesarean section, EXCEPT:', '["Metoclopramide","Glycopyrollate","Sodium citrate","Clear fluids 1 hours pre-op"]'::jsonb, 3, 'While clear fluids up to about 2 hours preoperatively are permitted by modern fasting guidelines, this option describes fluids taken only 1 hour pre-op, which does not meet the recommended fasting interval.', 'Anaesthesia & Perioperative Care', '💉', true),
(4404, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'All are suitable techniques for pain relief in labor EXCEPT:', '["Transcutaneous electrical nerve stimulation","Epidural bupivacaine","Intrathecal narcotics","70% Nitrous oxide in Oxygen"]'::jsonb, 3, 'High-concentration nitrous oxide (70%) risks maternal hypoxia and is not standard for labour analgesia; Entonox for labour is typically a 50:50 nitrous oxide/oxygen mix.', 'Anaesthesia & Perioperative Care', '💉', true),
(4405, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'A 65 years old man scheduled for herniography under spinal anaesthesia with bupivacaine 0.5% after positioning the patient become agitated, apnic ,then his BP pressure 80/45 mmgh , pulse rate 40/min ,Spo2 80% what is the possible cause ?', '["Residual effect of anaesthesia","Local anaesthesia toxicity","Shock","Status epilepticus"]'::jsonb, 1, 'Sudden agitation, apnoea, severe hypotension, bradycardia, and hypoxia shortly after a high-dose local anaesthetic injection are classic features of local anaesthetic systemic toxicity (LAST).', 'Anaesthesia & Perioperative Care', '💉', true),
(4406, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Regarding depolarizing muscle relaxant metabolism which is correct', '["Under go Hoffman elimination","Metabolized by acetyl choline esterase","Metabolized in the liver","Hydrolyzed in plasma psedocholine esterase"]'::jsonb, 1, 'Depolarising muscle relaxants such as succinylcholine are hydrolysed by plasma (pseudo)cholinesterase, not by acetylcholinesterase (a different enzyme found at the neuromuscular junction).', 'Anaesthesia & Perioperative Care', '💉', true),
(4407, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Symptoms of circulatory systemic overload during excessive IV fluids include all except:', '["Oliguria","Increased B/P","Anxiety","Pulmonary edema"]'::jsonb, 0, 'Fluid/circulatory overload typically causes increased (not decreased) urine output, along with dyspnoea, distended neck veins, and crackles; oliguria points toward hypovolaemia instead.', 'Anaesthesia & Perioperative Care', '💉', true),
(4408, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Life threatening risks of anesthesia include all except:', '["Hypoxic brain injury","Myocardial infarction","Postoperative nausea and vomiting","Cerebrovascular accident"]'::jsonb, 2, 'Postoperative nausea and vomiting is unpleasant but not life-threatening, unlike airway loss, anaphylaxis, or cardiovascular collapse, which are recognised life-threatening anaesthesia risks.', 'Anaesthesia & Perioperative Care', '💉', true),
(4409, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Ketamine; all are true except:', '["Induction of anesthesia by IV route","Induction of anesthesia …","Supplementation of sedation...","Decrease cerebral blood flow"]'::jsonb, 3, 'Ketamine is a dissociative agent that typically increases (not decreases) cerebral blood flow and intracranial pressure, distinguishing it from most other induction agents.', 'Anaesthesia & Perioperative Care', '💉', true),
(4410, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Signs of low perfusion include all except:', '["hypotension","tachycardia","High Urine Output","Poor Capillary refill"]'::jsonb, 2, 'Low perfusion states cause reduced (not high) urine output, along with delayed capillary refill, hypotension, and cool extremities.', 'Anaesthesia & Perioperative Care', '💉', true),
(4411, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Balanced General Anesthesia includes:', '["Skeletal muscle relaxant","Loss of consciousness","Analgesia","All of the above"]'::jsonb, 3, 'Balanced general anaesthesia combines hypnosis, analgesia, and muscle relaxation using a combination of agents to achieve each component with lower doses of any single drug.', 'Anaesthesia & Perioperative Care', '💉', true),
(4412, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Depolarizing block may be done by:', '["Atracurium","Neostegmin","Succinylcholine","rocuronuim"]'::jsonb, 2, 'Succinylcholine produces its neuromuscular block by persistent depolarisation of the motor endplate.', 'Anaesthesia & Perioperative Care', '💉', true),
(4413, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Intravenous regional anesthesia is more commonly used for operations of:', '["Neck surgeries","Lower abdomen","Upper limbs","Lower limbs"]'::jsonb, 2, 'Intravenous regional anaesthesia (Bier''s block) is most commonly used for short procedures on the upper limb using a double tourniquet technique.', 'Anaesthesia & Perioperative Care', '💉', true),
(4414, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Regarding morphine, all are true Except:', '["Respiratory depression effect","Can be IV subcutaneously, rectally and epidurally","Can cause nausea and vomiting","Less effective against pain of myocardial ischemia"]'::jsonb, 3, 'Morphine is generally considered less effective than agents with more specific anti-ischaemic/vasodilatory profiles for pain of myocardial ischaemia, though it remains widely used adjunctively.', 'Anaesthesia & Perioperative Care', '💉', true),
(4415, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Body Mass Index is', '["Height in centimeters / Weight (kg)","Weight (kg) / Height (M2)","Height (M2) / Weight (kg)","Weight (kg) / Height in centimeters"]'::jsonb, 1, 'BMI is calculated as weight in kilograms divided by height in metres squared (kg/m²).', 'Anaesthesia & Perioperative Care', '💉', true),
(4416, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'ASA III is:', '["normal, healthy patient","Patient with mild, well controlled systemic disease","Patient with sever systemic disease that limits activity","Patient with sever life threatening disease"]'::jsonb, 2, 'ASA III describes a patient with severe systemic disease that limits activity but is not incapacitating.', 'Anaesthesia & Perioperative Care', '💉', true),
(4417, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Premedication that can be give before anaesthesia:', '["Anxiolysis","Anti- emetic","Antacid","all of the above"]'::jsonb, 3, 'Premedication may include anxiolysis, antiemetic, and antacid components depending on patient needs, so ''all of the above'' is correct.', 'Anaesthesia & Perioperative Care', '💉', true),
(4418, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Mallampati grade suggests difficult intubation:', '["grade I","grade II","grade IV","All of the above"]'::jsonb, 2, 'Higher Mallampati grades (III-IV), which show little to no visibility of pharyngeal structures, are associated with more difficult laryngoscopy and intubation.', 'Anaesthesia & Perioperative Care', '💉', true),
(4419, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Factor at increase risk of aspiration includes:', '["drinking clear fluids 8 hours before operation","gastro esophageal reflux","chewing gum","Two hours preoperative oral clear fluid administration"]'::jsonb, 1, 'Gastro-oesophageal reflux increases the risk of regurgitation and pulmonary aspiration during induction of anaesthesia.', 'Anaesthesia & Perioperative Care', '💉', true),
(4420, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'In 70 kg patient one unit of platelet concentrate should increase platelet count:', '["2000 - 5000 / mm3","5000 - 10000 / mm3","10000 - 20000 / mm3","More than 20000 / mm3"]'::jsonb, 1, 'One unit of platelet concentrate is generally expected to raise the platelet count by roughly 5,000-10,000/mm3 in an average adult.', 'Anaesthesia & Perioperative Care', '💉', true),
(4421, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'The following are the classical hemolytic transfusion reaction in general anesthesia except:', '["Hypotension","Wheezing","Hemoglobinuria","bradycardia"]'::jsonb, 3, 'Classical acute haemolytic transfusion reaction features hypotension, wheezing, and haemoglobinuria from rapid red cell destruction; bradycardia is not a hallmark feature (reflex tachycardia is more typical).', 'Anaesthesia & Perioperative Care', '💉', true),
(4422, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'The mean arterial pressure of a blood pressure of 160 / 80 is:', '["90 mmHg","100 mmHg","110 mmHg","120 mmHg"]'::jsonb, 2, 'Mean arterial pressure ≈ DBP + 1/3(SBP-DBP) = 80 + 1/3(160-80) ≈ 107mmHg, closest to the 110mmHg option among the choices given.', 'Anaesthesia & Perioperative Care', '💉', true),
(4423, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Indication of rapid sequence anesthesia includes all except:', '["Patient ASA I undergoing elective cholecytectomy.","Patient presented with bowel obstruction","Morbid Obesity Patients","Pregnancy"]'::jsonb, 0, 'Rapid sequence induction is reserved for patients at increased aspiration risk (bowel obstruction, obesity, pregnancy); a fasted, low-risk ASA I patient for elective surgery does not require it.', 'Anaesthesia & Perioperative Care', '💉', true),
(4424, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Thiopental (sodium thiopental, Thiopentone, STP) characterized by the following except:', '["Prepares as a pale yellow 10.5 (alkaline)","After iv bolus, rapid","Effects include decrease cerebral blood flow and O2 requirements","Has good analgesic"]'::jsonb, 3, 'Thiopental provides hypnosis without meaningful analgesic properties, unlike some other anaesthetic adjuncts.', 'Anaesthesia & Perioperative Care', '💉', true),
(4425, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Ephedrine is best used with one of the following condition', '["Peripheral vasodilatation","Hypertension","General Anaestheisa","Local infiltration"]'::jsonb, 0, 'Ephedrine, an indirect-acting sympathomimetic, is useful for anaesthesia-related hypotension from peripheral vasodilatation, raising both heart rate and blood pressure.', 'Anaesthesia & Perioperative Care', '💉', true),
(4426, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Propofol is best used for', '["Induction of anaesthesia","Recovery from anaesthesia","Regional anaesthesia","Hypertensive patient"]'::jsonb, 0, 'Propofol''s rapid onset and clear-headed recovery profile make it a popular agent for induction of anaesthesia.', 'Anaesthesia & Perioperative Care', '💉', true),
(4427, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Endotracheal tube is best used for', '["Maintaining airway in anaesthetized patient","Reducing secretions during regional anaesthesia","Esophageal intubation","Spinal anaesthesia"]'::jsonb, 0, 'An endotracheal tube secures and protects the airway, providing a definitive route for ventilation in an anaesthetised patient.', 'Anaesthesia & Perioperative Care', '💉', true),
(4428, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Oral airway is contraindicated in one of the following conditions', '["Deeply anaesthetized patients","Full conscious patient","Comatose patient","Pediatric patient"]'::jsonb, 1, 'An oropharyngeal (oral) airway can trigger gagging, laryngospasm, or vomiting in a fully conscious patient with intact airway reflexes, so it is reserved for the unconscious/obtunded.', 'Anaesthesia & Perioperative Care', '💉', true),
(4429, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Nasal airway is not indicated in one of the following', '["Basal skull fracture","Full conscious patient","Comatose patient","Pediatric patient"]'::jsonb, 0, 'A nasal airway risks intracranial passage and is avoided in suspected basal skull fracture, particularly with signs like CSF rhinorrhoea or panda eyes.', 'Anaesthesia & Perioperative Care', '💉', true),
(4430, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Laryngeal mask air way is not used in one of the following cases', '["Patient with short period operation","Patient with operation in face","Patient with full stomach","Patient with operation in lower part of the body"]'::jsonb, 2, 'A laryngeal mask airway does not protect against aspiration and is avoided in patients with a full stomach or high aspiration risk.', 'Anaesthesia & Perioperative Care', '💉', true),
(4431, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Halothane is', '["Local anaesthetics agent","Volatile anaesthetics agent","General anaesthetic agent","Intravenous anaesthetic agent"]'::jsonb, 1, 'Halothane is a volatile (inhalational) general anaesthetic agent.', 'Anaesthesia & Perioperative Care', '💉', true),
(4432, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Xylocaine is contraindicated in one of the following', '["Children","General anaesthesia","Infection in the area of injection","Long operations"]'::jsonb, 2, 'Lidocaine (xylocaine) should be avoided for local infiltration into infected tissue, since local anaesthetics are less effective in the acidic, inflamed environment and injection may spread infection.', 'Anaesthesia & Perioperative Care', '💉', true),
(4433, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Pancuronium is', '["Depolarizing muscle relaxant","Short acting muscle relaxant","Long acting muscle relaxant","Intravenous anaesthetics agent"]'::jsonb, 2, 'Pancuronium is a long-acting non-depolarising neuromuscular blocking agent.', 'Anaesthesia & Perioperative Care', '💉', true),
(4434, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Neostigmine is used to', '["Increase the action of muscle relaxant","Reduce the action of muscle relaxant","To reverse the action of non depolarizing muscle relaxant","To increase the action of depolarizing muscle relaxant"]'::jsonb, 2, 'Neostigmine, an acetylcholinesterase inhibitor, increases available acetylcholine at the neuromuscular junction to reverse non-depolarising muscle relaxant blockade.', 'Anaesthesia & Perioperative Care', '💉', true),
(4435, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'The MAC of halothane is', '["102","0.75","75","1"]'::jsonb, 3, 'Halothane''s minimum alveolar concentration (MAC) is approximately 0.75%, one of the lowest (most potent) MAC values among volatile agents.', 'Anaesthesia & Perioperative Care', '💉', true),
(4436, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Protamine sulphate is antidote of', '["Heparin","Ephedrine","Pethadine","Scoline"]'::jsonb, 0, 'Protamine sulfate binds and neutralises heparin, reversing its anticoagulant effect.', 'Anaesthesia & Perioperative Care', '💉', true),
(4437, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Dextrose is contraindicated in one of the following', '["Hypotension","Hypertension","Pulmonary edema","Diabetics"]'::jsonb, 2, 'Dextrose-containing fluids can worsen fluid overload and are used cautiously in conditions like pulmonary oedema.', 'Anaesthesia & Perioperative Care', '💉', true),
(4438, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Atracurium is muscle relaxant which is', '["Metabolized by liver","Metabolized by kidney","Metabolized by Hoffman degradation","Contraindicated in renal transplant"]'::jsonb, 2, 'Atracurium is uniquely metabolised via Hofmann elimination (spontaneous degradation independent of liver/kidney function), useful in organ failure.', 'Anaesthesia & Perioperative Care', '💉', true),
(4439, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Diazepam is used for', '["General anaesthesia","Sedation with local anaesthesia","Increasing the effect of anaesthesia","Reversing anaesthesia"]'::jsonb, 1, 'Diazepam provides sedation and anxiolysis and is commonly used as an adjunct with local/regional anaesthesia.', 'Anaesthesia & Perioperative Care', '💉', true),
(4440, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Marcaine is', '["Muscle relaxant","Local anaesthetics agent","Analgesics","Hypertensive agent"]'::jsonb, 1, 'Marcaine (bupivacaine) is a long-acting amide local anaesthetic agent.', 'Anaesthesia & Perioperative Care', '💉', true),
(4441, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'The pKa values of most amides are similar; therefore,', '["onsets are rapid","Onsets are slow.","Onsets are similar.","Onsets have no effect."]'::jsonb, 2, 'Amide local anaesthetics with similar pKa values tend to have similar onset times, since pKa determines the proportion of unionised drug available to cross nerve membranes.', 'Anaesthesia & Perioperative Care', '💉', true),
(4442, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Concentration of Lidocaine used for spinal anaesthesia is', '["2%","5%","0.2%","0.25%"]'::jsonb, 1, 'Lidocaine for spinal anaesthesia is typically used at a higher concentration, around 5%, in hyperbaric preparations.', 'Anaesthesia & Perioperative Care', '💉', true),
(4443, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Ketamine is best used for', '["General anaesthesia","Local anaesthesia","Sedation in ICU","Pain relieve in post operative period"]'::jsonb, 0, 'Ketamine''s dissociative, analgesic, and amnesic properties make it well suited for general anaesthesia, particularly in haemodynamically unstable or resource-limited settings.', 'Anaesthesia & Perioperative Care', '💉', true),
(4444, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Pethidine side effects include all except', '["Nausea","Vomiting","Respiratory depression","Tachycardia"]'::jsonb, 3, 'Pethidine (meperidine) is not particularly associated with tachycardia as a defining side effect, unlike its recognised risks of nausea, respiratory depression, and (with repeated dosing) seizures from the norpethidine metabolite.', 'Anaesthesia & Perioperative Care', '💉', true),
(4445, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Nasal prongs used to give oxygen at flow of', '["1-2 liter","3-4 liter","5-6 liter","7-8 liter"]'::jsonb, 0, 'Standard nasal prongs/cannula are typically used at low flow rates of about 1-2 L/min for supplemental oxygen (limited by mucosal drying at higher flows).', 'Anaesthesia & Perioperative Care', '💉', true),
(4446, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'To reduce post dural puncture head ache with spinal we use', '["Small fine spinal needle","Tohy needle","Wide bore spinal needle","Syringe"]'::jsonb, 0, 'Using a smaller-gauge (fine) spinal needle reduces the size of the dural puncture and lowers the risk of post-dural puncture headache.', 'Anaesthesia & Perioperative Care', '💉', true),
(4447, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Inadequate urine output (oligiuria) is defined as', '["Urine output of 0.5 ml/kg body weight/hour","Urine output of less than 0.5 ml/kg body weight /hour","Urine output of more than 0.5 ml/kg body weight/ hour","Urine output of 5 ml/kg body weight /hour"]'::jsonb, 1, 'Oliguria in adults is generally defined as urine output less than 0.5 mL/kg/hour.', 'Anaesthesia & Perioperative Care', '💉', true),
(4448, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Which one of the following drugs increase the serum potassium', '["Succinylcholine","Pancuronium","Atracurium","Xylocaine"]'::jsonb, 0, 'Succinylcholine causes a transient rise in serum potassium as part of its depolarising action, a concern in patients at risk of hyperkalaemia.', 'Anaesthesia & Perioperative Care', '💉', true),
(4449, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'The motor contraction called fasciculation is seen after the use of one of the following', '["Suxamethonium","Pavlun","Marcaine","Pethadine"]'::jsonb, 0, 'Fasciculations (visible muscle twitching) are a characteristic effect of succinylcholine (suxamethonium) after administration.', 'Anaesthesia & Perioperative Care', '💉', true),
(4450, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Pulse oximetry can measure all of the following except', '["O2","Pulse","CO2","blood pressure"]'::jsonb, 2, 'Pulse oximetry measures oxygen saturation (and pulse rate) using light absorption; it does not measure carbon dioxide levels.', 'Anaesthesia & Perioperative Care', '💉', true),
(4451, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'in anaphylactic shock , all of the following are present except', '["hypotension","laryngeal spasm","congested neck veins","wheezy chest"]'::jsonb, 2, 'In anaphylactic shock, vasodilation and capillary leak cause hypotension with collapsed (not congested) neck veins, distinguishing it from cardiogenic causes of shock.', 'Anaesthesia & Perioperative Care', '💉', true),
(4452, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Correct Flowmeter rate with Nonrebreathing mask is', '["5 -9","10 -15","16 -20","21 -25"]'::jsonb, 0, 'A non-rebreathing mask requires a flow rate of roughly 5-9 (up to about 10-15) L/min to keep the reservoir bag inflated and deliver a high FiO2.', 'Anaesthesia & Perioperative Care', '💉', true),
(4453, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Central Venous Catheters is used to measure central venous pressure the normal is :', '["8-10 mmgh","11-15 mmgh","16-20 mmgh","21-25 mmgh"]'::jsonb, 0, 'Normal central venous pressure is generally cited as roughly 2-8mmHg; central lines are used to measure this parameter to help assess volume status.', 'Anaesthesia & Perioperative Care', '💉', true),
(4454, 'Anaesthesia MCQ Pool', 'MCQ Pool 2025 (Anaesthesia)', 'Acetyl cholinesterase decreasing the breakdown of released ACh; they exert :', '["Both nicotinic and muscarinic effects.","Nicotinic effects","Muscarinic effects","Adrenergic effects"]'::jsonb, 0, 'Acetylcholinesterase inhibitors like neostigmine increase acetylcholine availability at both nicotinic (neuromuscular) and muscarinic (e.g. cardiac, glandular) receptor sites, which is why an antimuscarinic (e.g. glycopyrrolate) is co-administered.', 'Anaesthesia & Perioperative Care', '💉', true),
(4455, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient in the ICU develops signs of urinary retention postoperatively. What intervention should the nurse implement?', '["Encourage increased fluid intake","Insert a urinary catheter","Administer stool softeners","Initiate physical therapy"]'::jsonb, 1, 'Bladder catheterisation drains the retained urine when a patient cannot void, relieving bladder distension.', 'Anaesthesia & Perioperative Care', '💉', true),
(4456, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient in the ICU presents with symptoms of paralytic ileus. What nursing action should be prioritized?', '["Administering antiemetic medication","Encouraging early ambulation","Maintaining nothing-by-mouth status","Monitoring bowel sounds"]'::jsonb, 1, 'Early ambulation stimulates peristalsis and helps resolve paralytic ileus.', 'Anaesthesia & Perioperative Care', '💉', true),
(4457, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient in the ICU develops organ injury postoperatively. Which laboratory test result would the nurse expect to be abnormal?', '["Elevated creatinine levels","Decreased platelet count","Low white blood cell count","Increased hemoglobin levels"]'::jsonb, 0, 'Elevated creatinine reflects impaired renal function, the laboratory marker most directly affected by postoperative kidney/organ injury.', 'Anaesthesia & Perioperative Care', '💉', true),
(4458, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'Nutritional deficiencies can occur postoperatively in the ICU. Which vitamin deficiency is commonly seen in surgical patients?', '["Vitamin A","Vitamin B12","Vitamin C","Vitamin D"]'::jsonb, 1, 'Vitamin B12 and other nutrient deficiencies are recognised risks after major surgery, particularly with reduced intake or malabsorption.', 'Anaesthesia & Perioperative Care', '💉', true),
(4459, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient in the ICU develops urinary retention as a postoperative complication. Which intervention should the nurse implement to address this issue?', '["Encourage the patient to drink plenty of fluids","Insert a urinary catheter","Administer diuretic medications","Encourage frequent ambulation"]'::jsonb, 1, 'Inserting a urinary catheter provides immediate bladder decompression when a patient cannot void postoperatively.', 'Anaesthesia & Perioperative Care', '💉', true),
(4460, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient in the postoperative period develops a fever. What intervention should the nurse implement first?', '["Administer acetaminophen to reduce the fever","Encourage the patient to drink plenty of fluids","Assess the surgical site for signs of infection","Apply cold compresses to the forehead"]'::jsonb, 2, 'A new postoperative fever should prompt assessment of the surgical site, since surgical site infection is a common and important cause.', 'Anaesthesia & Perioperative Care', '💉', true),
(4461, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'Wound dehiscence is a potential complication postoperatively. What action should the nurse take if a patient''s wound begins to dehisce?', '["Apply steri-strips to secure the wound edges","Leave the wound open to air out","Notify the healthcare provider immediately","Apply a pressure dressing over the wound"]'::jsonb, 2, 'Suspected wound dehiscence should be reported to the healthcare provider immediately so it can be assessed and managed before evisceration risk increases.', 'Anaesthesia & Perioperative Care', '💉', true),
(4462, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient in the ICU develops a postoperative ileus. What intervention should the nurse implement to help alleviate the ileus?', '["Encourage the patient to eat a high-fiber diet","Administer laxatives to promote bowel movements","Insert a nasogastric tube for decompression","Encourage the patient to perform deep breathing exercises"]'::jsonb, 2, 'Nasogastric decompression relieves gastric/bowel distension and reduces nausea and vomiting associated with postoperative ileus.', 'Anaesthesia & Perioperative Care', '💉', true),
(4463, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient develops a wound infection postoperatively. What is the priority nursing intervention for managing a wound infection?', '["Administering antibiotics as prescribed","Changing the dressing daily","Applying a warm compress to the wound","Irrigating the wound with normal saline"]'::jsonb, 0, 'Antibiotic therapy targeted at the causative organism is the priority intervention for a diagnosed wound infection.', 'Anaesthesia & Perioperative Care', '💉', true),
(4464, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'Which of the following postoperative complications involves the abnormal accumulation of fluid at the surgical site?', '["Urinary retention","Paralytic ileus","Adhesion formation","Seroma"]'::jsonb, 3, 'A seroma is a localised collection of serous fluid at the surgical site.', 'Anaesthesia & Perioperative Care', '💉', true),
(4465, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'What intervention is essential in preventing urinary retention postoperatively?', '["Encouraging early ambulation","Administering laxatives","Increasing fluid intake","Reducing oral intake"]'::jsonb, 0, 'Early ambulation promotes normal bladder tone and reduces the risk of postoperative urinary retention.', 'Anaesthesia & Perioperative Care', '💉', true),
(4466, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'Which postoperative complication can lead to atrial fibrillation and other cardiac issues?', '["Pneumonia","Delayed wound healing","Heart complications","Stroke"]'::jsonb, 2, 'Postoperative cardiac complications, including new arrhythmias such as atrial fibrillation, are a recognised risk after surgery, particularly in patients with cardiac risk factors.', 'Anaesthesia & Perioperative Care', '💉', true),
(4467, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'What intervention is crucial in preventing organ injury or damage postoperatively?', '["Monitoring vital signs","Administering antibiotics","Encouraging coughing and deep breathing","Providing pain management"]'::jsonb, 0, 'Close vital sign and haemodynamic monitoring helps detect early signs of organ hypoperfusion or injury before it becomes severe.', 'Anaesthesia & Perioperative Care', '💉', true),
(4468, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient in the postoperative period experiences delayed wound healing. Which factor should be assessed to determine the cause?', '["Blood pressure","Blood glucose levels","White blood cell count","Respiratory rate"]'::jsonb, 1, 'Elevated blood glucose impairs wound healing, so glycaemic control is assessed as a contributing factor to delayed healing.', 'Anaesthesia & Perioperative Care', '💉', true),
(4469, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient develops respiratory failure postoperatively. Which intervention is a priority in managing this complication?', '["Administering pain medication","Placing the patient in a semi-Fowler''s position","Providing supplemental oxygen","Encouraging deep breathing exercises"]'::jsonb, 2, 'Supplemental oxygen is a priority intervention to correct hypoxaemia in postoperative respiratory failure while the underlying cause is addressed.', 'Anaesthesia & Perioperative Care', '💉', true),
(4470, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'In postoperative care, what is a common complication associated with inadequate pain management?', '["Increased appetite","Respiratory depression","Urinary retention","Hypotension"]'::jsonb, 1, 'Under-treated pain can suppress respiratory effort indirectly through splinting/shallow breathing, but more directly, opioid analgesics used to treat pain carry a dose-dependent risk of respiratory depression.', 'Anaesthesia & Perioperative Care', '💉', true),
(4471, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient develops a postoperative ileus. Which intervention is appropriate to help promote bowel function?', '["Encouraging ambulation","Restricting fluid intake","Administering laxatives","Providing a high-fiber diet"]'::jsonb, 0, 'Ambulation stimulates bowel motility and helps resolve postoperative ileus.', 'Anaesthesia & Perioperative Care', '💉', true),
(4472, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient is at risk for developing blood clots postoperatively. Which intervention is essential to prevent this complication?', '["Administering blood thinners as prescribed","Encouraging bedrest and immobilization","Increasing salt intake","Applying warm compress to the affected area"]'::jsonb, 0, 'Prophylactic anticoagulants (blood thinners) reduce the risk of venous thromboembolism in patients at risk for postoperative blood clots.', 'Anaesthesia & Perioperative Care', '💉', true),
(4473, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'Following surgery, a patient develops signs of seroma formation. Which intervention is appropriate for managing this complication?', '["Applying heat packs to the area","Manual compression to the affected site","Drainage of the fluid through a needle","Encouraging increased fluid intake"]'::jsonb, 2, 'Needle drainage removes the accumulated fluid and relieves a symptomatic seroma.', 'Anaesthesia & Perioperative Care', '💉', true),
(4474, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A postoperative patient is found to have signs of infection at the surgical site. What is the most appropriate action by the nurse?', '["Apply ice to reduce swelling","Keep the wound dry and uncovered","Administer prescribed antibiotics","Perform frequent dressing changes"]'::jsonb, 2, 'Prescribed antibiotics treat the underlying infection at the surgical site.', 'Anaesthesia & Perioperative Care', '💉', true),
(4475, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A postoperative patient is experiencing paralytic ileus. What nursing intervention is appropriate for managing this complication?', '["Encouraging ambulation as tolerated","Administering antiemetic medications","Maintaining NPO status","Providing high-fiber diet"]'::jsonb, 2, 'Keeping the patient NPO reduces gastric contents and vomiting risk while bowel motility is absent during paralytic ileus.', 'Anaesthesia & Perioperative Care', '💉', true),
(4476, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'Which postoperative complication is most likely to occur in a patient with a history of deep vein thrombosis (DVT)?', '["Organ injury","Paralytic ileus","Pulmonary embolism","Urinary retention"]'::jsonb, 2, 'A history of DVT increases the risk that a dislodged clot will travel to the pulmonary circulation, causing a pulmonary embolism.', 'Anaesthesia & Perioperative Care', '💉', true),
(4477, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A postoperative patient is found to have a large amount of fluid accumulation at the surgical site. What intervention should the nurse implement?', '["Apply compression bandages","Encourage more intake of fluids","Perform sterile drainage of the seroma","Apply ice packs to reduce swelling"]'::jsonb, 2, 'Sterile needle drainage of a large, symptomatic seroma relieves the fluid collection while minimising infection risk.', 'Anaesthesia & Perioperative Care', '💉', true),
(4478, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'Which postoperative complication is commonly associated with inadequate postoperative respiratory care?', '["Infection","Wound dehiscence","Respiratory distress","Bleeding"]'::jsonb, 2, 'Inadequate postoperative respiratory care (poor deep breathing/coughing) predisposes to atelectasis and respiratory distress.', 'Anaesthesia & Perioperative Care', '💉', true),
(4479, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A postoperative patient has persistent bleeding at the surgical site. What should be the nurse''s first action?', '["Apply pressure and elevate the limb","Administer pain medication","Perform a dressing change","Notify the healthcare provider"]'::jsonb, 0, 'Direct pressure and limb elevation are first-line measures to control active bleeding at a surgical site while further help is obtained.', 'Anaesthesia & Perioperative Care', '💉', true),
(4480, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient develops pneumonia postoperatively due to decreased lung function. What is the priority nursing intervention?', '["Administering pain medication","Positioning for optimal breathing","Encouraging fluid intake","Providing emotional support"]'::jsonb, 1, 'Positioning that optimises lung expansion (e.g. semi- to high-Fowler''s) supports oxygenation and secretion clearance in postoperative pneumonia.', 'Anaesthesia & Perioperative Care', '💉', true),
(4481, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'Nerve damage can occur as a complication of surgery. Which assessment finding should the nurse prioritize in a patient with suspected nerve damage?', '["Sensory changes","Increased heart rate","Elevated temperature","Abdominal pain"]'::jsonb, 0, 'Sensory changes (numbness, altered sensation) are a key assessment finding suggesting postoperative nerve injury.', 'Anaesthesia & Perioperative Care', '💉', true),
(4482, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient develops signs of nutritional deficiencies postoperatively. What intervention should the nurse prioritize?', '["Ordering a protein-rich diet","Initiating total parenteral nutrition (TPN)","Consulting a dietitian","Administering vitamin supplements"]'::jsonb, 2, 'A dietitian consultation supports individualised nutritional assessment and repletion planning for a patient with postoperative nutritional deficiency.', 'Anaesthesia & Perioperative Care', '💉', true),
(4483, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'How can kidney failure be managed in a patient postoperatively in the ICU?', '["Increasing fluid intake","Administering diuretics","Providing hemodialysis","Restricting protein intake"]'::jsonb, 2, 'Haemodialysis provides renal replacement therapy to manage postoperative kidney failure when medical management is insufficient.', 'Anaesthesia & Perioperative Care', '💉', true),
(4484, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'What intervention is beneficial in preventing stroke in a postoperative patient in the ICU?', '["Administering anticoagulants","Encouraging ambulation","Limiting fluid intake","Monitoring temperature"]'::jsonb, 0, 'Prophylactic anticoagulation reduces thromboembolic stroke risk in patients at elevated risk postoperatively.', 'Anaesthesia & Perioperative Care', '💉', true),
(4485, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'What action should be taken in preparation for potential organ injury postoperatively in the ICU?', '["Administering pain medication","Monitoring lab values","Encouraging coughing and deep breathing","Applying warm compresses"]'::jsonb, 1, 'Monitoring relevant laboratory values (e.g. renal function tests) allows early detection of postoperative organ injury.', 'Anaesthesia & Perioperative Care', '💉', true),
(4486, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient experiences a postoperative incisional hernia. What should be included in the nursing care plan?', '["Encouraging lifting heavy objects","Reinforcing the surgical incision with glue","Promoting early ambulation","Application of heat pads to the hernia site"]'::jsonb, 2, 'Early ambulation reduces intra-abdominal pressure spikes from straining and supports overall recovery, forming part of hernia-risk-reducing postoperative care.', 'Anaesthesia & Perioperative Care', '💉', true),
(4487, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'Postoperatively, a patient develops urinary retention. What is the priority nursing action?', '["Encouraging decreased fluid intake","Providing a bedside commode","Initiating intermittent catheterization","Administering diuretics"]'::jsonb, 2, 'Intermittent catheterisation empties the bladder as needed while preserving bladder tone better than an indwelling catheter for postoperative urinary retention.', 'Anaesthesia & Perioperative Care', '💉', true),
(4488, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient experiences postoperative ileus. What intervention should the nurse prioritize?', '["Increasing fiber intake","Encouraging early ambulation","Administering laxatives","Withholding nutrition"]'::jsonb, 1, 'Early ambulation promotes return of normal peristalsis in postoperative ileus.', 'Anaesthesia & Perioperative Care', '💉', true),
(4489, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'What is a common sign of infection in a postoperative patient?', '["Increased appetite","Decreased white blood cell count","Redness and warmth at the surgical site","Decreased pain at the incision site"]'::jsonb, 2, 'Redness and warmth at the surgical site are classic local signs of wound infection.', 'Anaesthesia & Perioperative Care', '💉', true),
(4490, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient develops excessive bleeding postoperatively. What should be the initial nursing action?', '["Applying pressure to the bleeding site","Providing a warm compress","Administering more pain medication","Elevating the affected limb"]'::jsonb, 0, 'Direct pressure over the bleeding site is the initial action to control postoperative bleeding.', 'Anaesthesia & Perioperative Care', '💉', true),
(4491, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient in the ICU develops a seroma at the surgical site. What nursing intervention is appropriate?', '["Aspirating the seroma with a syringe","Applying direct pressure to the seroma","Removing the seroma surgically","Applying a warm compress to the seroma"]'::jsonb, 0, 'Needle aspiration removes the fluid collection of a seroma at the surgical site.', 'Anaesthesia & Perioperative Care', '💉', true),
(4492, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'What is a common cause of postoperative fever in ICU patients?', '["Infection","Dehydration","Medication side effects","Hypothermia"]'::jsonb, 0, 'Infection is one of the most common causes of new fever in postoperative ICU patients and should be actively investigated.', 'Anaesthesia & Perioperative Care', '💉', true),
(4493, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient in the ICU develops signs of sepsis postoperatively. What intervention should the nurse prioritize?', '["Administering pain medication","Initiating intravenous fluids","Providing oxygen therapy","Checking vital signs frequently"]'::jsonb, 1, 'IV fluid resuscitation is a priority in postoperative sepsis to support perfusion, alongside prompt antibiotics and source control.', 'Anaesthesia & Perioperative Care', '💉', true),
(4494, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient in the ICU is at risk for developing a pressure ulcer postoperatively. What nursing interventions can help prevent this complication?', '["Repositioning the patient every 2 hours","Keeping the head of the bed elevated","Massaging bony prominences","Applying direct pressure to areas at risk"]'::jsonb, 0, 'Repositioning at least every 2 hours relieves sustained pressure over bony prominences, reducing pressure ulcer risk.', 'Anaesthesia & Perioperative Care', '💉', true),
(4495, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'An ICU patient develops signs of delirium postoperatively. What nursing interventions are appropriate for managing delirium?', '["Administering sedatives","Ensuring a quiet environment","Encouraging fluid intake","Limiting communication with the patient"]'::jsonb, 1, 'A calm, quiet, and appropriately oriented environment reduces sensory overload that can worsen postoperative delirium.', 'Anaesthesia & Perioperative Care', '💉', true),
(4496, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A postoperative ICU patient is at risk for developing urinary retention. What nursing interventions can help prevent urinary retention?', '["Limiting fluid intake","Encouraging ambulation","Inserting a catheter","Providing a bedside commode"]'::jsonb, 1, 'Ambulation promotes normal bladder emptying and reduces urinary retention risk in postoperative ICU patients.', 'Anaesthesia & Perioperative Care', '💉', true),
(4497, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient in the ICU develops signs of hypovolemic shock postoperatively. What interventions should the nurse prioritize?', '["Administering vasopressors","Increasing IV fluid rate","Monitoring vital signs closely","Elevating the legs"]'::jsonb, 1, 'Increasing IV fluid administration restores circulating volume in hypovolaemic shock.', 'Anaesthesia & Perioperative Care', '💉', true),
(4498, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A postoperative ICU patient is at risk for developing pneumonia. What nursing interventions can help prevent pneumonia?', '["Providing supplemental oxygen","Administering antibiotics prophylactically","Encouraging deep breathing exercises and coughing","Maintaining strict isolation precautions"]'::jsonb, 2, 'Deep breathing exercises and coughing help clear secretions and prevent atelectasis, reducing postoperative pneumonia risk.', 'Anaesthesia & Perioperative Care', '💉', true),
(4499, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient in the ICU is at risk for developing delirium. What nursing interventions can help prevent delirium?', '["Keeping the environment quiet and calm","Administering sedatives regularly","Restraining the patient to prevent wandering","Limiting visitation from family members"]'::jsonb, 0, 'A calm, quiet environment with orientation cues helps prevent and manage ICU delirium.', 'Anaesthesia & Perioperative Care', '💉', true),
(4500, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'An ICU patient is experiencing pain postoperatively. What interventions can the nurse implement to manage the patient''s pain effectively?', '["Administering pain medications as needed","Limiting the use of pain medications to prevent dependence","Applying ice packs to the surgical site","Encouraging the patient to tough it out"]'::jsonb, 0, 'Scheduled or as-needed analgesia, guided by ongoing pain assessment, is the mainstay of effective postoperative pain management.', 'Anaesthesia & Perioperative Care', '💉', true),
(4501, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient in the ICU is experiencing nausea and vomiting. What interventions can help alleviate these symptoms?', '["Administering anti-emetics","Limiting oral intake to clear liquids only","Encouraging the patient to eat a full meal","Placing the patient in Trendelenburg position"]'::jsonb, 0, 'Antiemetics directly target the nausea/vomiting pathway to relieve symptoms.', 'Anaesthesia & Perioperative Care', '💉', true),
(4502, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'An ICU patient is at risk for developing complications related to immobility. What nursing interventions can help prevent complications of immobility?', '["Encouraging regular range of motion exercises","Restraining the patient to prevent falls","Keeping the patient in bed at all times","Limiting bathroom privileges"]'::jsonb, 0, 'Regular range-of-motion exercises help prevent the deconditioning, contractures, and thromboembolic risks associated with immobility.', 'Anaesthesia & Perioperative Care', '💉', true),
(4503, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'An ICU patient has a nasogastric tube in place. What interventions should the nurse prioritize when caring for a patient with a nasogastric tube?', '["Keeping the tube open to gravity at all times","Monitoring for signs of tube displacement and ensuring proper placement","Clamping the tube when not in use","Removing the tube to allow the patient to eat"]'::jsonb, 1, 'Confirming correct nasogastric tube placement and monitoring for displacement prevents misdirected feeds/medications and aspiration risk.', 'Anaesthesia & Perioperative Care', '💉', true),
(4504, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient in the ICU is on mechanical ventilation. What nursing interventions are important to maintain ventilator function and prevent complications?', '["Monitoring ventilator settings and alarms regularly","Limiting suctioning to prevent infection","Disconnecting the patient from the ventilator periodically for breaks","Administering sedatives to keep the patient calm"]'::jsonb, 0, 'Regular monitoring of ventilator settings and alarms helps detect and correct problems (e.g. disconnection, high pressures) before they harm the patient.', 'Anaesthesia & Perioperative Care', '💉', true),
(4505, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'An ICU patient has a central venous catheter in place. What nursing interventions are essential to prevent complications associated with central lines?', '["Maintaining a sterile technique during catheter care and dressing changes","Keeping the catheter site dry and exposed to air","Removing the catheter as soon as possible to prevent infection","Allowing family members to touch the catheter site"]'::jsonb, 0, 'Strict sterile technique during central line care and dressing changes reduces the risk of catheter-related bloodstream infection.', 'Anaesthesia & Perioperative Care', '💉', true),
(4506, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient in the ICU is at risk for developing pressure ulcers. What nursing interventions can help prevent pressure ulcers in this patient?', '["Turning the patient every 2 hours","Applying a barrier cream to protect the skin","Using sheepskin or foam padding to reduce pressure","Keeping the patient on a firm mattress at all times"]'::jsonb, 0, 'Turning the patient at least every 2 hours relieves pressure on bony prominences, reducing pressure ulcer risk.', 'Anaesthesia & Perioperative Care', '💉', true),
(4507, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient in the ICU is at risk for developing delirium. What nursing interventions can help prevent or manage delirium in this patient?', '["Maintaining a quiet and calm environment","Using physical restraints to prevent agitation","Administering sedatives to keep the patient quiet","Encouraging family members to visit frequently"]'::jsonb, 0, 'A calm, quiet environment with consistent orientation supports prevention and management of ICU delirium.', 'Anaesthesia & Perioperative Care', '💉', true),
(4508, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient in the ICU is experiencing pain. What nursing interventions can help manage the patient''s pain effectively?', '["Administering pain medication as prescribed","Limiting the patient''s access to pain medication","Encouraging the patient to ignore the pain","Assuming the patient is exaggerating the pain"]'::jsonb, 0, 'Prescribed analgesia, individualised to the patient''s reported pain, is the primary approach to effective pain management.', 'Anaesthesia & Perioperative Care', '💉', true),
(4509, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A post-operative patient is at risk for developing adhesion formation. What nursing interventions can help prevent or minimize adhesion formation?', '["Encourage deep breathing exercises","Apply warm compresses to the surgical site","Administer antibiotics prophylactically","Prevent unnecessary manipulation of the surgical site"]'::jsonb, 3, 'Minimising unnecessary handling/manipulation of the surgical site reduces additional tissue trauma that contributes to adhesion formation.', 'Anaesthesia & Perioperative Care', '💉', true),
(4510, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient develops a seroma following surgery. What nursing interventions are important for managing a seroma?', '["Apply pressure dressings over the seroma","Administer diuretics to reduce fluid accumulation","Perform needle aspiration to drain the seroma","Keep the patient immobile to prevent fluid movement"]'::jsonb, 2, 'Needle aspiration drains a symptomatic seroma.', 'Anaesthesia & Perioperative Care', '💉', true),
(4511, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient post-surgery experiences a hematoma at the surgical site. What nursing interventions are appropriate for managing a hematoma?', '["Apply ice packs to the hematoma site","Encourage the patient to avoid movement to prevent bleeding","Administer anticoagulant medications","Monitor for signs of infection around the hematoma"]'::jsonb, 0, 'Ice packs (cold therapy) reduce swelling and limit further bleeding into the tissue in an acute postoperative hematoma.', 'Anaesthesia & Perioperative Care', '💉', true),
(4512, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient is at risk for developing a pressure ulcer following surgery. What nursing interventions can help prevent pressure ulcers in the post-operative period?', '["Turn and reposition the patient regularly","Apply direct pressure to bony prominences","Encourage the patient to lie on the affected side","Use tight dressings to prevent skin breakdown"]'::jsonb, 0, 'Regular turning and repositioning relieves pressure over bony prominences, reducing pressure ulcer risk.', 'Anaesthesia & Perioperative Care', '💉', true),
(4513, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient is experiencing post-operative pain. What nursing interventions can be implemented to help manage the patient''s pain effectively?', '["Administer pain medication as ordered and assess pain levels regularly","Encourage the patient to tough it out and not ask for pain medication","Apply heat to the surgical site to alleviate pain","Limit the patient''s fluid intake to decrease discomfort"]'::jsonb, 0, 'Regularly scheduled analgesia with ongoing pain reassessment is the mainstay of effective postoperative pain control.', 'Anaesthesia & Perioperative Care', '💉', true),
(4514, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient is experiencing post-operative nausea and vomiting. What nursing interventions can help manage these symptoms?', '["Administer anti-nausea medication as ordered","Encourage the patient to eat large meals to prevent hunger-induced nausea","Offer the patient strong-smelling foods to mask the smell of vomit","Encourage the patient to lie flat to reduce nausea"]'::jsonb, 0, 'Antiemetic medication directly targets postoperative nausea and vomiting.', 'Anaesthesia & Perioperative Care', '💉', true),
(4515, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient develops a urinary tract infection (UTI) following surgery. What nursing interventions can be implemented to manage a UTI?', '["Encourage the patient to hold their urine to strengthen the bladder","Ensure proper hygiene and cleanliness when using the bathroom","Limit the patient''s fluid intake to reduce urinary frequency","Administer antibiotics as prescribed"]'::jsonb, 3, 'Antibiotics targeted at the causative organism treat a diagnosed postoperative urinary tract infection.', 'Anaesthesia & Perioperative Care', '💉', true),
(4516, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient develops post-operative respiratory complications. What nursing interventions can help manage respiratory complications in the post-operative period?', '["Encourage deep breathing exercises and use of incentive spirometry","Keep the patient in a supine position at all times","Administer sedatives to keep the patient calm and reduce respiratory effort","Encourage smoking to help open up the airways"]'::jsonb, 0, 'Deep breathing exercises and incentive spirometry help re-expand alveoli and prevent atelectasis after surgery.', 'Anaesthesia & Perioperative Care', '💉', true),
(4517, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient is at risk for developing deep vein thrombosis (DVT) following surgery. What nursing interventions can help prevent DVT in the post-operative period?', '["Encourage the patient to remain sedentary and avoid moving around","Apply compression stockings as ordered","Keep the patient well-hydrated to prevent blood clots","Elevate the patient''s legs above heart level at all times"]'::jsonb, 1, 'Graduated compression stockings promote venous return and reduce DVT risk in postoperative patients.', 'Anaesthesia & Perioperative Care', '💉', true),
(4518, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient is experiencing post-operative confusion and delirium. What nursing interventions can help manage confusion and delirium in the post-operative period?', '["Maintain a quiet and calm environment for the patient","Encourage the patient to stay up late and engage in stimulating activities","Administer sedatives to keep the patient calm","Limit family visits to prevent overstimulation"]'::jsonb, 0, 'A calm, quiet, and consistently oriented environment helps manage postoperative confusion and delirium.', 'Anaesthesia & Perioperative Care', '💉', true),
(4519, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient is at risk for developing deep vein thrombosis (DVT) following surgery. What nursing interventions can help prevent DVT in the post-operative period?', '["Encourage early ambulation and leg exercises","Apply compression stockings as ordered","Administer anticoagulant medication as prescribed","Keep the patient''s legs elevated above heart level"]'::jsonb, 0, 'Early ambulation and leg exercises promote venous return, reducing venous stasis and DVT risk.', 'Anaesthesia & Perioperative Care', '💉', true),
(4520, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient is at risk for developing post-operative respiratory complications. What nursing interventions can help prevent respiratory complications in the post-operative period?', '["Encourage deep breathing and coughing exercises","Administer oxygen as ordered","Encourage the patient to lie flat in bed","Limit the patient''s fluid intake to prevent pulmonary edema"]'::jsonb, 0, 'Deep breathing and coughing exercises help clear secretions and re-expand the lungs, preventing postoperative respiratory complications.', 'Anaesthesia & Perioperative Care', '💉', true),
(4521, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient is at risk for developing post-operative ileus. What nursing interventions can help prevent or manage post-operative ileus?', '["Encourage early ambulation and activity","Administer laxatives as ordered","Encourage the patient to avoid consuming fluids","Apply heat to the abdomen to promote bowel motility"]'::jsonb, 0, 'Early ambulation and activity stimulate bowel motility, helping prevent or resolve postoperative ileus.', 'Anaesthesia & Perioperative Care', '💉', true),
(4522, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient is at risk for developing post-operative delirium. What nursing interventions can help prevent or manage post-operative delirium?', '["Ensure a quiet and well-lit environment for the patient","Administer sedatives to keep the patient calm","Encourage the patient to stay awake for longer periods of time","Limit the patient''s fluid intake to decrease confusion"]'::jsonb, 0, 'A calm, appropriately lit, and well-oriented environment helps prevent or manage postoperative delirium.', 'Anaesthesia & Perioperative Care', '💉', true),
(4523, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient is at risk for developing post-operative pressure ulcers. What nursing interventions can help prevent pressure ulcers in the post-operative period?', '["Turn and reposition the patient regularly","Use pressure-relieving devices such as cushions or mattresses","Keep the patient''s skin clean and dry","Encourage the patient to sit up in bed for extended periods"]'::jsonb, 0, 'Regular turning and repositioning relieves sustained pressure, reducing postoperative pressure ulcer risk.', 'Anaesthesia & Perioperative Care', '💉', true),
(4524, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient is at risk for developing post-operative fluid and electrolyte imbalances. What nursing interventions can help prevent or manage fluid and electrolyte imbalances in the post- operative period?', '["Monitor the patient''s intake and output closely","Administer IV fluids as prescribed","Encourage the patient to limit fluid intake","Restrict the patient''s sodium intake"]'::jsonb, 0, 'Close monitoring of fluid intake and output helps detect and guide correction of postoperative fluid and electrolyte imbalances.', 'Anaesthesia & Perioperative Care', '💉', true),
(4525, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient is at risk for developing post-operative nausea and vomiting. What nursing interventions can help prevent or manage post-operative nausea and vomiting?', '["Administer antiemetic medications as ordered","Encourage the patient to eat a large meal immediately after surgery","Keep the patient NPO (nothing by mouth) to prevent nausea","Provide small, frequent meals and clear liquids as tolerated"]'::jsonb, 0, 'Antiemetic medication is the primary intervention to prevent and manage postoperative nausea and vomiting.', 'Anaesthesia & Perioperative Care', '💉', true),
(4526, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient is at risk for developing post-operative delirium. What nursing interventions can help prevent or manage post-operative delirium?', '["Keep the patient''s environment calm and quiet","Provide orientation cues such as clocks and calendars","Assist the patient with activities of daily living","Administer sedative medications to keep the patient calm"]'::jsonb, 0, 'A calm, quiet environment reduces overstimulation that can precipitate or worsen postoperative delirium.', 'Anaesthesia & Perioperative Care', '💉', true),
(4527, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient is at risk for developing post-operative venous thromboembolism (VTE). What nursing interventions can help prevent VTE in the post-operative period?', '["Encourage early ambulation and leg exercises","Apply sequential compression devices as prescribed","Administer anticoagulant medications as ordered","Keep the patient immobilized in bed to prevent movement"]'::jsonb, 0, 'Early ambulation and leg exercises promote venous return, reducing the risk of venous thromboembolism.', 'Anaesthesia & Perioperative Care', '💉', true),
(4528, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient is at risk for developing post-operative hypothermia. What nursing interventions can help prevent hypothermia in the post-operative period?', '["Use warming blankets or forced-air warming devices","Keep the patient''s room temperature cool","Limit the use of warm fluids and blankets","Monitor the patient''s temperature regularly"]'::jsonb, 0, 'Active warming measures (warmed blankets, forced-air warmers) help prevent and treat postoperative hypothermia.', 'Anaesthesia & Perioperative Care', '💉', true),
(4529, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient is at risk for developing post-operative infection. What nursing interventions can help prevent infection in the post-operative period?', '["Encourage proper hand hygiene for both the patient and healthcare providers","Monitor the surgical incision site for signs of infection","Administer prophylactic antibiotics as prescribed","Educate the patient on proper wound care techniques"]'::jsonb, 0, 'Consistent hand hygiene by both staff and patient is a foundational measure for preventing postoperative infection.', 'Anaesthesia & Perioperative Care', '💉', true),
(4530, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient is at risk for developing post-operative nausea and vomiting (PONV). What nursing interventions can help prevent PONV in the post-operative period?', '["Administer antiemetic medications as prescribed","Encourage the patient to drink clear liquids","Avoid administering opioids for pain management","Monitor the patient''s intake and output closely"]'::jsonb, 0, 'Antiemetic medication is the standard intervention to prevent and manage postoperative nausea and vomiting (PONV).', 'Anaesthesia & Perioperative Care', '💉', true),
(4531, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient is at risk for developing post-operative pressure ulcers. What nursing interventions can help prevent pressure ulcers in the post-operative period?', '["Reposition the patient regularly to relieve pressure on bony prominences","Use pressure-relieving devices such as cushions or mattresses","Keep the patient''s skin clean and dry","Encourage adequate nutrition and hydration for skin healing"]'::jsonb, 0, 'Regular repositioning relieves sustained pressure on bony prominences, the key preventive measure against pressure ulcers.', 'Anaesthesia & Perioperative Care', '💉', true),
(4532, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient is at risk for developing post-operative ileus. What nursing interventions can help prevent or manage post-operative ileus?', '["Encourage early ambulation and movement","Monitor bowel sounds and abdominal distention closely","Administer medications to promote bowel motility as prescribed","Encourage the patient to eat a high-fiber diet"]'::jsonb, 0, 'Encouraging early ambulation and movement stimulates bowel motility, helping prevent or manage postoperative ileus.', 'Anaesthesia & Perioperative Care', '💉', true),
(4533, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient is at risk for developing post-operative respiratory complications. What nursing interventions can help prevent respiratory complications in the post-operative period?', '["Encourage deep breathing exercises and coughing to prevent atelectasis","Monitor respiratory rate, oxygen saturation, and lung sounds regularly","Assist the patient with changing positions frequently to promote lung expansion","Administer respiratory treatments as prescribed, such as incentive spirometry"]'::jsonb, 0, 'Deep breathing and coughing exercises help re-expand the lungs and prevent atelectasis after surgery.', 'Anaesthesia & Perioperative Care', '💉', true),
(4534, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient is at risk for developing post-operative deep vein thrombosis (DVT). What nursing interventions can help prevent DVT in the post-operative period?', '["Encourage early mobilization and activity","Apply pneumatic compression devices to promote circulation","Administer anticoagulant medications as prescribed","Monitor for signs and symptoms of DVT, such as swelling or pain in one leg"]'::jsonb, 2, 'Prescribed anticoagulant medication reduces clot formation risk in patients at risk for postoperative DVT.', 'Anaesthesia & Perioperative Care', '💉', true),
(4535, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient is at risk for developing post-operative delirium. What nursing interventions can help prevent or manage delirium in the post-operative period?', '["Ensure a quiet and calm environment for the patient","Orient the patient to time, place, and person frequently","Encourage adequate hydration and nutrition","Monitor for changes in mental status and behavior"]'::jsonb, 1, 'Frequent reorientation to time, place, and person helps prevent and manage postoperative delirium.', 'Anaesthesia & Perioperative Care', '💉', true),
(4536, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient is at risk for developing post-operative urinary retention. What nursing interventions can help prevent or manage urinary retention in the post-operative period?', '["Encourage the patient to void regularly, even if they do not feel the urge","Monitor intake and output closely","Assist the patient with toileting as needed","Use bladder ultrasound or intermittent catheterization as necessary"]'::jsonb, 0, 'Encouraging regular voiding attempts helps prevent postoperative urinary retention from progressing.', 'Anaesthesia & Perioperative Care', '💉', true),
(4537, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient is at risk for developing post-operative fluid and electrolyte imbalances. What nursing interventions can help prevent or manage fluid and electrolyte imbalances in the post- operative period?', '["Monitor daily weights and assess for signs of dehydration or overload","Administer IV fluids as prescribed to maintain fluid balance","Encourage adequate fluid intake to prevent dehydration","Monitor electrolyte levels and adjust diet or medications as needed"]'::jsonb, 0, 'Trending daily weights helps detect fluid retention or loss, guiding management of postoperative fluid and electrolyte balance.', 'Anaesthesia & Perioperative Care', '💉', true),
(4538, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient is at risk for developing post-operative pressure injuries. What nursing interventions can help prevent pressure injuries in the post-operative period?', '["Implement a schedule for turning and repositioning the patient regularly","Use pressure-relieving devices such as cushions or mattresses","Keep the skin clean and dry to prevent breakdown","Assess bony prominences frequently for signs of redness or breakdown"]'::jsonb, 0, 'A scheduled turning and repositioning programme is the core preventive measure against postoperative pressure injuries.', 'Anaesthesia & Perioperative Care', '💉', true),
(4539, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient is at risk for developing post-operative sepsis. What nursing interventions can help prevent sepsis in the post-operative period?', '["Monitor vital signs for signs of infection, such as fever or tachycardia","Ensure proper hand hygiene and sterile technique during wound care","Administer antibiotics as prescribed to treat infections promptly","Educate the patient on signs and symptoms of infection to report immediately"]'::jsonb, 0, 'Close vital sign monitoring for fever or tachycardia allows early recognition of developing postoperative sepsis.', 'Anaesthesia & Perioperative Care', '💉', true),
(4540, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient is at risk for developing post-operative gastrointestinal complications. What nursing interventions can help prevent or manage gastrointestinal complications in the post- operative period?', '["Advance the patient''s diet as tolerated to prevent ileus","Monitor bowel sounds and assess for abdominal distension or pain","Administer antiemetic medications as prescribed to control nausea and vomiting","Encourage ambulation and early mobilization to promote GI motility"]'::jsonb, 1, 'Monitoring bowel sounds and abdominal distension helps detect and guide management of postoperative gastrointestinal complications such as ileus.', 'Anaesthesia & Perioperative Care', '💉', true),
(4541, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient is at risk for developing post-operative respiratory complications. What nursing interventions can help prevent or manage respiratory complications in the post-operative period?', '["Encourage deep breathing and coughing exercises to prevent atelectasis","Monitor oxygen saturation levels and respiratory rate regularly","Assist the patient with early ambulation to prevent pneumonia","Provide supplemental oxygen as prescribed by the healthcare provider"]'::jsonb, 0, 'Deep breathing and coughing exercises help prevent atelectasis, a common postoperative respiratory complication.', 'Anaesthesia & Perioperative Care', '💉', true),
(4542, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient is at risk for developing post-operative venous thromboembolism (VTE). What nursing interventions can help prevent VTE in the post-operative period?', '["Encourage early ambulation and leg exercises to promote circulation","Utilize compression stockings or sequential compression devices","Administer anticoagulant medications as prescribed by the healthcare provider","Educate the patient on signs and symptoms of VTE to report immediately"]'::jsonb, 0, 'Early ambulation and leg exercises promote venous return, helping prevent postoperative venous thromboembolism.', 'Anaesthesia & Perioperative Care', '💉', true),
(4543, 'Post-Operative Complications', 'Post-Operative Complications MCQs (class study document)', 'A patient is at risk for developing post-operative urinary retention. What nursing interventions can help prevent or manage urinary retention in the post-operative period?', '["Assist the patient with toileting every 2-3 hours","Monitor bladder scan results and assess for signs of urinary retention","Encourage adequate fluid intake to promote urinary flow","Insert a urinary catheter as needed to empty the bladder"]'::jsonb, 1, 'Bladder scanning helps confirm urinary retention so it can be promptly addressed, such as with catheterisation if needed.', 'Anaesthesia & Perioperative Care', '💉', true),
(4544, 'IV Fluids & Tonicity', 'Class study material (WhatsApp share)', 'Isotonic solution means:', '["Higher solute than cell","Lower solute than cell","Equal solute concentration as cell","No solute"]'::jsonb, 2, 'Isotonic solutions have the same solute concentration (osmolarity) as the cell, so no net fluid shift occurs.', 'Renal & Fluid Balance', '💧', true),
(4545, 'IV Fluids & Tonicity', 'Class study material (WhatsApp share)', 'Hypotonic solution has:', '["More solute than cell","Less solute than cell","Equal solute","No water"]'::jsonb, 1, 'A hypotonic solution has a lower solute concentration than the cell, so water moves into the cell.', 'Renal & Fluid Balance', '💧', true),
(4546, 'IV Fluids & Tonicity', 'Class study material (WhatsApp share)', 'Hypertonic solution has:', '["Less solute","Equal solute","More solute than cell","No solute"]'::jsonb, 2, 'A hypertonic solution has a higher solute concentration than the cell, drawing water out of it.', 'Renal & Fluid Balance', '💧', true),
(4547, 'IV Fluids & Tonicity', 'Class study material (WhatsApp share)', 'In isotonic solution, cell will:', '["Swell","Shrink","Remain same","Burst"]'::jsonb, 2, 'With equal osmotic pressure inside and out, the cell neither gains nor loses net water in an isotonic solution.', 'Renal & Fluid Balance', '💧', true),
(4548, 'IV Fluids & Tonicity', 'Class study material (WhatsApp share)', 'In hypotonic solution, cell will:', '["Shrink","Swell","No change","Die immediately"]'::jsonb, 1, 'Water moves into the cell down its concentration gradient in a hypotonic solution, causing swelling.', 'Renal & Fluid Balance', '💧', true),
(4549, 'IV Fluids & Tonicity', 'Class study material (WhatsApp share)', 'In hypertonic solution, cell will:', '["Swell","Shrink","Burst","No change"]'::jsonb, 1, 'Water moves out of the cell into the more concentrated surrounding fluid in a hypertonic solution, causing shrinkage.', 'Renal & Fluid Balance', '💧', true),
(4550, 'IV Fluids & Tonicity', 'Class study material (WhatsApp share)', 'Which is isotonic solution?', '["0.9% Normal saline","0.45% saline","3% saline","D5W"]'::jsonb, 0, '0.9% normal saline has essentially the same osmolarity as blood plasma, making it isotonic.', 'Renal & Fluid Balance', '💧', true),
(4551, 'IV Fluids & Tonicity', 'Class study material (WhatsApp share)', 'Which is hypotonic solution?', '["0.9% saline","0.45% saline","5% dextrose","3% saline"]'::jsonb, 1, '0.45% saline (''half-normal saline'') has roughly half the solute concentration of plasma, making it hypotonic.', 'Renal & Fluid Balance', '💧', true),
(4552, 'IV Fluids & Tonicity', 'Class study material (WhatsApp share)', 'Which is hypertonic solution?', '["0.9% saline","0.45% saline","3% saline","Water"]'::jsonb, 2, '3% saline has a much higher solute concentration than plasma, making it markedly hypertonic.', 'Renal & Fluid Balance', '💧', true),
(4553, 'IV Fluids & Tonicity', 'Class study material (WhatsApp share)', 'Isotonic solution is used for:', '["Dehydration","Shock","Fluid replacement","All of the above"]'::jsonb, 3, 'Isotonic fluids expand intravascular volume without shifting fluid between compartments, making them suitable for dehydration, shock, and general fluid replacement.', 'Renal & Fluid Balance', '💧', true);
